/**
 * 一个轻量级的BP神经网络实现，支持动态层级和训练可视化
 */

export class BPNetwork {
  layers: number[];
  weights: number[][][]; // [layer][target][source]
  biases: number[][];    // [layer][neuron]
  learningRate: number;

  constructor(layers: number[], learningRate: number = 0.1) {
    this.layers = layers;
    this.learningRate = learningRate;
    this.weights = [];
    this.biases = [];

    // 初始化权重和偏置
    for (let i = 0; i < layers.length - 1; i++) {
      const layerWeights: number[][] = [];
      const layerBiases: number[] = [];
      for (let j = 0; j < layers[i + 1]; j++) {
        const neuronWeights: number[] = [];
        for (let k = 0; k < layers[i]; k++) {
          neuronWeights.push(Math.random() * 2 - 1); // -1 to 1
        }
        layerWeights.push(neuronWeights);
        layerBiases.push(Math.random() * 2 - 1);
      }
      this.weights.push(layerWeights);
      this.biases.push(layerBiases);
    }
  }

  sigmoid(x: number): number {
    return 1 / (1 + Math.exp(-x));
  }

  sigmoidDeriv(x: number): number {
    const s = this.sigmoid(x);
    return s * (1 - s);
  }

  feedForward(inputs: number[]): number[][] {
    let current = inputs;
    const activations = [inputs];

    for (let i = 0; i < this.weights.length; i++) {
      const next: number[] = [];
      for (let j = 0; j < this.weights[i].length; j++) {
        let sum = this.biases[i][j];
        for (let k = 0; k < current.length; k++) {
          sum += current[k] * this.weights[i][j][k];
        }
        next.push(this.sigmoid(sum));
      }
      current = next;
      activations.push(current);
    }
    return activations;
  }

  train(inputs: number[], targets: number[]): number {
    const activations = this.feedForward(inputs);
    const deltas: number[][] = [];

    // 计算输出层误差
    const outputLayerIndex = this.layers.length - 1;
    const outputActivations = activations[outputLayerIndex];
    const outputDeltas: number[] = [];
    let loss = 0;
    for (let i = 0; i < outputActivations.length; i++) {
      const error = targets[i] - outputActivations[i];
      loss += error * error;
      outputDeltas.push(error * outputActivations[i] * (1 - outputActivations[i]));
    }
    deltas[outputLayerIndex - 1] = outputDeltas;

    // 反向传播误差
    for (let i = outputLayerIndex - 2; i >= 0; i--) {
      const currentDeltas: number[] = [];
      const nextDeltas = deltas[i + 1];
      const nextWeights = this.weights[i + 1];
      const currentActivations = activations[i + 1];

      for (let j = 0; j < this.layers[i + 1]; j++) {
        let error = 0;
        for (let k = 0; k < nextDeltas.length; k++) {
          error += nextDeltas[k] * nextWeights[k][j];
        }
        currentDeltas.push(error * currentActivations[j] * (1 - currentActivations[j]));
      }
      deltas[i] = currentDeltas;
    }

    // 更新权重和偏置
    for (let i = 0; i < this.weights.length; i++) {
      for (let j = 0; j < this.weights[i].length; j++) {
        for (let k = 0; k < this.weights[i][j].length; k++) {
          this.weights[i][j][k] += this.learningRate * deltas[i][j] * activations[i][k];
        }
        this.biases[i][j] += this.learningRate * deltas[i][j];
      }
    }

    return loss / 2;
  }
}

import { GoogleGenAI } from "@google/genai";

export const getAIInsights = async (config: any, stats: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `
    我正在运营一个BP神经网络可视化实验室。
    当前网络配置如下：
    - 输入层神经元：${config.layers[0]}
    - 隐藏层：${config.layers.slice(1, -1).join(', ') || '无'}
    - 输出层神经元：${config.layers[config.layers.length - 1]}
    - 学习率：${config.learningRate}

    目前的训练统计数据：
    - 已训练轮次 (Epoch)：${stats.epoch}
    - 当前损失值 (Loss)：${stats.loss.toFixed(6)}

    请根据以上数据提供一份“AI专家洞察”。
    要求：
    1. 评价当前网络结构的合理性。
    2. 对当前的损失值下降情况给出解释或优化建议。
    3. 用简明专业的中文回答。
    4. 采用Markdown格式。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "暂时无法获取AI洞察，请检查网络或API配置。";
  }
};

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface NetworkGraphProps {
  layers: number[];
  weights: number[][][];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ layers, weights }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;
    const margin = 50;

    const layerSpacing = (width - 2 * margin) / (layers.length - 1 || 1);

    const nodes: any[] = [];
    const nodeMap: { [key: string]: any } = {};

    // Create Nodes
    layers.forEach((count, lIdx) => {
      const x = margin + lIdx * layerSpacing;
      const vertSpacing = (height - 2 * margin) / (count || 1);
      const startY = margin + (height - 2 * margin - (count - 1) * vertSpacing) / 2;

      for (let i = 0; i < count; i++) {
        const id = `l${lIdx}n${i}`;
        const node = { id, x, y: startY + i * vertSpacing, layer: lIdx };
        nodes.push(node);
        nodeMap[id] = node;
      }
    });

    // Create Edges
    const edges: any[] = [];
    for (let l = 0; l < weights.length; l++) {
      for (let j = 0; j < weights[l].length; j++) {
        for (let k = 0; k < weights[l][j].length; k++) {
          edges.push({
            source: nodeMap[`l${l}n${k}`],
            target: nodeMap[`l${l+1}n${j}`],
            weight: weights[l][j][k]
          });
        }
      }
    }

    // Draw Edges
    svg.append("g")
      .selectAll("line")
      .data(edges)
      .enter()
      .append("line")
      .attr("x1", d => d.source.x)
      .attr("y1", d => d.source.y)
      .attr("x2", d => d.target.x)
      .attr("y2", d => d.target.y)
      .attr("stroke", d => d.weight > 0 ? "#60a5fa" : "#f87171")
      .attr("stroke-width", d => Math.abs(d.weight) * 2 + 0.5)
      .attr("opacity", 0.6);

    // Draw Nodes
    svg.append("g")
      .selectAll("circle")
      .data(nodes)
      .enter()
      .append("circle")
      .attr("cx", d => d.x)
      .attr("cy", d => d.y)
      .attr("r", 12)
      .attr("fill", "white")
      .attr("stroke", "#3b82f6")
      .attr("stroke-width", 2);

    svg.append("g")
      .selectAll("text")
      .data(nodes)
      .enter()
      .append("text")
      .attr("x", d => d.x)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "10px")
      .attr("font-weight", "bold")
      .attr("fill", "#1e40af")
      .text((d, i) => d.id.split('n')[1]);

  }, [layers, weights]);

  return (
    <div className="w-full h-full bg-white rounded-xl shadow-inner border border-blue-50 overflow-hidden">
      <svg ref={svgRef} className="w-full h-full" />
    </div>
  );
};

export default NetworkGraph;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { BPNetwork } from './services/bpEngine';
import NetworkGraph from './components/NetworkGraph';
import { getAIInsights } from './services/geminiService';

const DATASETS = {
  XOR: [
    { input: [0, 0], output: [0] },
    { input: [0, 1], output: [1] },
    { input: [1, 0], output: [1] },
    { input: [1, 1], output: [0] },
  ],
  AND: [
    { input: [0, 0], output: [0] },
    { input: [0, 1], output: [0] },
    { input: [1, 0], output: [0] },
    { input: [1, 1], output: [1] },
  ],
  OR: [
    { input: [0, 0], output: [0] },
    { input: [0, 1], output: [1] },
    { input: [1, 0], output: [1] },
    { input: [1, 1], output: [1] },
  ],
};

const App: React.FC = () => {
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);
  const [predictionInput, setPredictionInput] = useState<string>("0, 1");
  const [predictionOutput, setPredictionOutput] = useState<number | null>(null);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  const trainingRef = useRef<any>(null);

  const resetNetwork = useCallback(() => {
    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setPredictionOutput(null);
    setAiInsight("");
  }, [layers, learningRate]);

  const trainStep = useCallback(() => {
    if (!network) return;
    const dataset = DATASETS.XOR;
    let totalLoss = 0;
    dataset.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });

    const avgLoss = totalLoss / dataset.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);

    if (epoch % 10 === 0) {
      setHistory(prev => [...prev.slice(-49), { epoch, loss: avgLoss }]);
    }
  }, [network, epoch]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 10);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handlePredict = () => {
    const inputs = predictionInput.split(',').map(v => parseFloat(v.trim()));
    if (inputs.length !== layers[0]) {
      alert(`输入维度不匹配，需要 ${layers[0]} 个值`);
      return;
    }
    const result = network.feedForward(inputs);
    setPredictionOutput(result[result.length - 1][0]);
  };

  const handleGetInsight = async () => {
    setIsAiLoading(true);
    const insight = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss });
    setAiInsight(insight || "");
    setIsAiLoading(false);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6">
      {/* Header */}
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div>
          <h1 className="text-3xl font-extrabold text-blue-600 tracking-tight">BP神经网络可视化实验室</h1>
          <p className="text-gray-500 mt-1">交互式神经网络学习与洞察平台</p>
        </div>
        <div className="flex gap-3 mt-4 md:mt-0">
          <button 
            onClick={() => setIsTraining(!isTraining)}
            className={`px-6 py-2 rounded-full font-semibold transition-all shadow-md ${isTraining ? 'bg-red-500 text-white hover:bg-red-600' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
          >
            {isTraining ? '停止训练' : '开始训练'}
          </button>
          <button 
            onClick={resetNetwork}
            className="px-6 py-2 rounded-full bg-white border border-gray-200 text-gray-700 font-semibold hover:bg-gray-50 transition-all shadow-sm"
          >
            重置网络
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-grow">

        {/* Left Control Panel */}
        <section className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <span className="w-2 h-6 bg-blue-500 rounded-full"></span>
              架构配置
            </h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">输入层神经元: {layers[0]}</label>
                <input type="range" min="1" max="5" value={layers[0]} onChange={e => setLayers([parseInt(e.target.value), layers[1], layers[2]])} className="w-full accent-blue-600" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">隐藏层神经元: {layers[1]}</label>
                <input type="range" min="1" max="10" value={layers[1]} onChange={e => setLayers([layers[0], parseInt(e.target.value), layers[2]])} className="w-full accent-blue-600" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">输出层神经元: {layers[2]}</label>
                <input type="range" min="1" max="1" value={layers[2]} disabled className="w-full accent-gray-400" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">学习率: {learningRate}</label>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full accent-blue-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <span className="w-2 h-6 bg-green-500 rounded-full"></span>
              在线预测
            </h2>
            <div className="space-y-4">
              <p className="text-xs text-gray-400">输入示例 (XOR): 1, 0</p>
              <input 
                type="text" 
                value={predictionInput}
                onChange={e => setPredictionInput(e.target.value)}
                className="w-full p-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
              />
              <button 
                onClick={handlePredict}
                className="w-full py-2 bg-green-600 text-white rounded-lg font-medium hover:bg-green-700 transition-colors"
              >
                预测输出
              </button>
              {predictionOutput !== null && (
                <div className="mt-4 p-4 bg-green-50 rounded-xl border border-green-100 text-center">
                  <span className="text-sm text-green-600 font-medium">结果: </span>
                  <span className="text-2xl font-bold text-green-800">{predictionOutput.toFixed(4)}</span>
                </div>
              )}
            </div>
          </div>
        </section>

        {/* Center Visualization */}
        <section className="lg:col-span-6 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow relative min-h-[400px]">
             <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <span className="w-2 h-6 bg-indigo-500 rounded-full"></span>
              神经网络结构图 (实线颜色代表权重正负)
            </h2>
            <NetworkGraph layers={layers} weights={network.weights} />
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[250px]">
            <h2 className="text-lg font-bold mb-4 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <span className="w-2 h-6 bg-red-400 rounded-full"></span>
                训练统计
              </div>
              <div className="text-xs font-normal text-gray-500">
                Epoch: {epoch} | Loss: {currentLoss.toFixed(6)}
              </div>
            </h2>
            <div className="w-full h-40">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={history}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="epoch" hide />
                  <YAxis domain={[0, 'auto']} tick={{fontSize: 10}} />
                  <Tooltip labelClassName="text-gray-800" />
                  <Line type="monotone" dataKey="loss" stroke="#ef4444" strokeWidth={2} dot={false} isAnimationActive={false} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </div>
        </section>

        {/* Right AI Insight Panel */}
        <section className="lg:col-span-3 flex flex-col">
          <div className="bg-gradient-to-br from-blue-50 to-indigo-50 p-6 rounded-2xl shadow-sm border border-blue-100 flex-grow flex flex-col">
            <h2 className="text-lg font-bold mb-4 flex items-center justify-between text-blue-800">
              <div className="flex items-center gap-2">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                AI 洞察
              </div>
              <button 
                onClick={handleGetInsight}
                disabled={isAiLoading}
                className={`text-xs px-3 py-1 rounded-full bg-blue-600 text-white hover:bg-blue-700 transition-all ${isAiLoading ? 'opacity-50' : ''}`}
              >
                {isAiLoading ? '分析中...' : '深度分析'}
              </button>
            </h2>

            <div className="flex-grow overflow-y-auto text-sm text-gray-700 leading-relaxed custom-scrollbar">
              {aiInsight ? (
                <div className="prose prose-sm prose-blue max-w-none">
                  <div dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>') }} />
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-40">
                  <svg className="w-12 h-12 mb-2 text-blue-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                  <p>点击上方按钮<br/>获取针对当前模型的AI分析</p>
                </div>
              )}
            </div>
          </div>
        </section>
      </main>

      {/* Footer Info */}
      <footer className="mt-4 text-center text-xs text-gray-400">
        &copy; 2024 BP神经网络可视化实验室 - 使用 Google Gemini 驱动洞察
      </footer>
    </div>
  );
};

