import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ScatterChart, Scatter, ZAxis, Legend, ReferenceLine } from 'recharts';
import { BPNetwork } from './services/bpEngine';
import NetworkGraph from './components/NetworkGraph';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  // 基础配置状态
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [sampleSize, setSampleSize] = useState(100);

  // 数据集状态
  const [trainData, setTrainData] = useState<{ input: number[], output: number[] }[]>([]);
  const [testData, setTestData] = useState<{ input: number[], output: number[] }[]>([]);

  // 神经网络引擎状态
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);

  // 预测对比结果
  const [testResults, setTestResults] = useState<{ actual: number; predicted: number }[]>([]);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  const trainingRef = useRef<any>(null);

  // 模拟复杂非线性函数的数据生成
  const generateData = useCallback(() => {
    const inputDim = layers[0];
    const outputDim = layers[layers.length - 1];

    const newData = Array.from({ length: sampleSize }, () => {
      const input = Array.from({ length: inputDim }, () => Math.random() * 2 - 1);
      const output = Array.from({ length: outputDim }, (_, i) => {
        // 构建每个输出维度的目标值
        const base = Math.sin(input[0] * Math.PI) * Math.cos((input[1] || 1) * Math.PI);
        const shift = i * 0.3; // 不同输出维度的偏移
        return Math.max(0, Math.min(1, (base + shift + 1) / 2)); 
      });
      return { input, output };
    });

    const splitIdx = Math.floor(newData.length * 0.7);
    setTrainData(newData.slice(0, splitIdx));
    setTestData(newData.slice(splitIdx));

    // 重置网络和状态
    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setTestResults([]);
    setAiInsight("");
  }, [layers, learningRate, sampleSize]);

  // 监听层级或样本大小变化，重置数据和模型
  useEffect(() => {
    generateData();
  }, [layers[0], layers[2], sampleSize]);

  const trainStep = useCallback(() => {
    if (!network || trainData.length === 0) return;

    let totalLoss = 0;
    trainData.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });

    const avgLoss = totalLoss / trainData.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);

    // 每隔一定轮次更新图表，提高性能
    if (epoch % 10 === 0) {
      setHistory(prev => [...prev.slice(-99), { epoch, loss: avgLoss }]);

      if (testData.length > 0) {
        const results = testData.map((d) => {
          const pred = network.feedForward(d.input);
          const finalPred = pred[pred.length - 1];
          // 如果是多输出，图表对比第一个维度的预测精度
          return {
            actual: d.output[0],
            predicted: finalPred[0]
          };
        });
        setTestResults(results);
      }
    }
  }, [network, epoch, trainData, testData]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 20);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handleGetInsight = async () => {
    setIsAiLoading(true);
    const insight = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss });
    setAiInsight(insight || "");
    setIsAiLoading(false);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6 font-sans">
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div>
          <h1 className="text-3xl font-extrabold text-blue-600 tracking-tight">BP神经网络交互实验室</h1>
          <p className="text-gray-500 mt-1">深度学习原理可视化与预测建模分析</p>
        </div>
        <div className="flex gap-3 mt-4 md:mt-0">
          <button 
            onClick={() => setIsTraining(!isTraining)}
            className={`px-8 py-2 rounded-full font-semibold transition-all shadow-md ${isTraining ? 'bg-orange-500 text-white hover:bg-orange-600' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
          >
            {isTraining ? '暂停训练' : '开始训练'}
          </button>
          <button 
            onClick={generateData}
            className="px-8 py-2 rounded-full bg-white border border-gray-200 text-gray-700 font-semibold hover:bg-gray-50 transition-all shadow-sm"
          >
            重置模型
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* 左侧配置栏 */}
        <section className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <span className="w-2 h-6 bg-blue-500 rounded-full"></span>
              网络架构配置
            </h2>
            <div className="space-y-5">
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-gray-600">输入层神经元</span>
                  <span className="font-bold text-blue-600">{layers[0]}</span>
                </div>
                <input type="range" min="1" max="5" value={layers[0]} onChange={e => setLayers([parseInt(e.target.value), layers[1], layers[2]])} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-gray-600">隐藏层神经元</span>
                  <span className="font-bold text-blue-600">{layers[1]}</span>
                </div>
                <input type="range" min="1" max="12" value={layers[1]} onChange={e => setLayers([layers[0], parseInt(e.target.value), layers[2]])} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-gray-600">输出层神经元</span>
                  <span className="font-bold text-blue-600">{layers[2]}</span>
                </div>
                <input type="range" min="1" max="3" value={layers[2]} onChange={e => setLayers([layers[0], layers[1], parseInt(e.target.value)])} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-gray-600">学习率</span>
                  <span className="font-bold text-blue-600">{learningRate}</span>
                </div>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <span className="w-2 h-6 bg-purple-500 rounded-full"></span>
              样本生成模块
            </h2>
            <div className="space-y-4">
              <div>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-gray-600">样本总数</span>
                  <span className="font-bold text-purple-600">{sampleSize}</span>
                </div>
                <input type="range" min="50" max="500" step="10" value={sampleSize} onChange={e => setSampleSize(parseInt(e.target.value))} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-purple-600" />
              </div>
              <div className="grid grid-cols-2 gap-3 text-center">
                <div className="p-3 bg-blue-50 rounded-xl border border-blue-100">
                  <div className="text-[10px] text-blue-500 font-bold mb-1">训练集 (70%)</div>
                  <div className="text-2xl font-black text-blue-700">{trainData.length}</div>
                </div>
                <div className="p-3 bg-indigo-50 rounded-xl border border-indigo-100">
                  <div className="text-[10px] text-indigo-500 font-bold mb-1">预测集 (30%)</div>
                  <div className="text-2xl font-black text-indigo-700">{testData.length}</div>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* 中央主显示区 */}
        <section className="lg:col-span-6 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow min-h-[420px] flex flex-col">
             <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <span className="w-2 h-6 bg-indigo-500 rounded-full"></span>
              网络结构演示
            </h2>
            <div className="flex-grow">
              <NetworkGraph layers={layers} weights={network.weights} />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[320px] flex flex-col">
              <h2 className="text-sm font-bold mb-4 flex items-center justify-between">
                <div className="flex items-center gap-2">
