            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[320px] flex flex-col">
              <h2 className="text-sm font-bold mb-4 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <span className="w-2 h-5 bg-emerald-400 rounded-full"></span>
                  预测 vs 真实值 (预测集)
                </div>
              </h2>
              <div className="flex-grow">
                <ResponsiveContainer width="100%" height="100%">
                  <ScatterChart margin={{ top: 10, right: 10, bottom: 20, left: -10 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f5f5f5" />
                    <XAxis type="number" dataKey="actual" name="真实值" domain={[0, 1]} tick={{fontSize: 10}} label={{ value: '真实值', position: 'insideBottom', offset: -10, fontSize: 10 }} />
                    <YAxis type="number" dataKey="predicted" name="预测值" domain={[0, 1]} tick={{fontSize: 10}} label={{ value: '预测值', angle: -90, position: 'insideLeft', fontSize: 10 }} />
                    <Tooltip cursor={{ strokeDasharray: '3 3' }} />
                    <Legend verticalAlign="top" height={30} iconType="circle" wrapperStyle={{fontSize: '11px'}} />
                    <ReferenceLine x={0} y={0} segment={[{ x: 0, y: 0 }, { x: 1, y: 1 }]} stroke="#cbd5e1" strokeDasharray="3 3" label={{ position: 'top', value: '理想线', fill: '#94a3b8', fontSize: 10 }} />
                    <Scatter name="预测点" data={testResults} fill="#3b82f6" fillOpacity={0.6} />
                  </ScatterChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </section>

        {/* AI 诊断面板 */}
        <section className="lg:col-span-3 flex flex-col">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow flex flex-col relative overflow-hidden">
            <div className="relative z-10 flex flex-col h-full">
              <h2 className="text-lg font-bold mb-4 flex items-center justify-between text-gray-800">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 bg-blue-600 rounded-lg">
                    <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                  </div>
                  AI 智能洞察
                </div>
              </h2>

              <div className="flex-grow overflow-y-auto text-sm text-gray-600 leading-relaxed pr-2 custom-scrollbar">
                {aiInsight ? (
                  <div className="prose prose-sm prose-blue max-w-none">
                     <div dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>').replace(/### (.*?)<br\/>/g, '<h3 class="font-bold text-blue-700 mt-4 mb-1">$1</h3>') }} />
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-center py-10">
                    <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mb-4">
                      <svg className="w-8 h-8 text-blue-400 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                    </div>
                    <p className="text-gray-400">开始训练后<br/>点击按钮获取模型架构评估</p>
                  </div>
                )}
              </div>

              <button 
                onClick={handleGetInsight}
                disabled={isAiLoading || epoch === 0}
                className={`mt-4 w-full py-3 rounded-xl font-bold shadow-lg transition-all ${
                  isAiLoading || epoch === 0 
                  ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                  : 'bg-gradient-to-r from-blue-600 to-indigo-600 text-white hover:shadow-xl active:scale-95'
                }`}
              >
                {isAiLoading ? '分析模型中...' : '生成模型诊断报告'}
              </button>
            </div>
          </div>
        </section>
      </main>

      <footer className="mt-4 text-center text-xs text-gray-400 pb-4">
        &copy; 2024 BP神经网络可视化实验室 · 赋能深度学习初学者
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
