};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ScatterChart, Scatter, ZAxis, Legend, ReferenceLine } from 'recharts';
import { BPNetwork } from './services/bpEngine';
import NetworkGraph from './components/NetworkGraph';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  // 基础配置状态
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [sampleSize, setSampleSize] = useState(120);

  // 数据集状态
  const [trainData, setTrainData] = useState<{ input: number[], output: number[] }[]>([]);
  const [testData, setTestData] = useState<{ input: number[], output: number[] }[]>([]);

  // 神经网络引擎状态
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);

  // 预测对比结果
  const [testResults, setTestResults] = useState<{ actual: number; predicted: number }[]>([]);
  const [isPredicting, setIsPredicting] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  const trainingRef = useRef<any>(null);

  // 模拟复杂非线性函数的数据生成
  const generateData = useCallback(() => {
    const inputDim = layers[0];
    const outputDim = layers[layers.length - 1];

    const newData = Array.from({ length: sampleSize }, () => {
      const input = Array.from({ length: inputDim }, () => Math.random() * 2 - 1);
      const output = Array.from({ length: outputDim }, (_, i) => {
        // 构建每个输出维度的目标值：使用非线性组合
        const base = Math.sin(input[0] * Math.PI) * Math.cos((input[1] || 1) * Math.PI);
        const shift = i * 0.3; 
        return Math.max(0, Math.min(1, (base + shift + 1) / 2)); 
      });
      return { input, output };
    });

    const splitIdx = Math.floor(newData.length * 0.7);
    setTrainData(newData.slice(0, splitIdx));
    setTestData(newData.slice(splitIdx));

    // 重置网络和状态
    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setTestResults([]);
    setAiInsight("");
    setIsTraining(false);
  }, [layers, learningRate, sampleSize]);

  // 执行预测与绘图：使用当前训练好的参数对预测集进行推理
  const runEvaluation = useCallback(() => {
    if (!network || testData.length === 0) return;
    setIsPredicting(true);

    // 模拟一个短暂的计算延迟，增强交互感
    setTimeout(() => {
      const results = testData.map((d) => {
        const activations = network.feedForward(d.input);
        const finalPred = activations[activations.length - 1];
        // 对于散点对比图，展示第一个输出维度的精度
        return {
          actual: d.output[0],
          predicted: finalPred[0]
        };
      });
      setTestResults(results);
      setIsPredicting(false);
    }, 300);
  }, [network, testData]);

  // 监听层级或样本大小变化，重置数据和模型
  useEffect(() => {
    generateData();
  }, [layers[0], layers[2], sampleSize]);

  const trainStep = useCallback(() => {
    if (!network || trainData.length === 0) return;

    let totalLoss = 0;
    trainData.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });

    const avgLoss = totalLoss / trainData.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);

    // 更新损失历史
    if (epoch % 5 === 0) {
      setHistory(prev => [...prev.slice(-99), { epoch, loss: avgLoss }]);
    }
  }, [network, epoch, trainData]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 20);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handleGetInsight = async () => {
    setIsAiLoading(true);
    const insight = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss });
    setAiInsight(insight || "");
    setIsAiLoading(false);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6 font-sans select-none">
      {/* 顶部标题栏 */}
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div>
          <h1 className="text-3xl font-extrabold text-blue-600 tracking-tight">BP神经网络交互实验室</h1>
          <p className="text-gray-500 mt-1 italic">构建 · 训练 · 预测 · 洞察</p>
        </div>
        <div className="flex gap-3 mt-4 md:mt-0">
          <button 
            onClick={() => setIsTraining(!isTraining)}
            className={`px-8 py-2 rounded-full font-bold transition-all shadow-md flex items-center gap-2 ${isTraining ? 'bg-amber-500 text-white hover:bg-amber-600' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
          >
            {isTraining ? (
              <><span className="w-2 h-2 bg-white rounded-full animate-ping"></span> 停止训练</>
            ) : (
              <><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M4.5 3L15.5 10L4.5 17V3Z"/></svg> 开始训练</>
            )}
          </button>
          <button 
            onClick={generateData}
            className="px-8 py-2 rounded-full bg-white border border-gray-200 text-gray-700 font-bold hover:bg-gray-50 transition-all shadow-sm"
          >
            重置环境
          </button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* 左侧配置栏 */}
        <section className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-lg font-black mb-4 flex items-center gap-2 text-gray-800">
              <span className="w-2 h-6 bg-blue-500 rounded-full"></span>
              架构建构模型
            </h2>
            <div className="space-y-5">
              <div>
                <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-wider text-gray-400">
                  <span>输入层 (Input)</span>
                  <span className="text-blue-600">{layers[0]}</span>
                </div>
                <input type="range" min="1" max="5" value={layers[0]} onChange={e => setLayers([parseInt(e.target.value), layers[1], layers[2]])} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div>
                <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-wider text-gray-400">
                  <span>隐藏层 (Hidden)</span>
                  <span className="text-blue-600">{layers[1]}</span>
                </div>
                <input type="range" min="1" max="12" value={layers[1]} onChange={e => setLayers([layers[0], parseInt(e.target.value), layers[2]])} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div>
                <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-wider text-gray-400">
                  <span>输出层 (Output)</span>
                  <span className="text-blue-600">{layers[2]}</span>
                </div>
                <input type="range" min="1" max="3" value={layers[2]} onChange={e => setLayers([layers[0], layers[1], parseInt(e.target.value)])} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div className="pt-2">
                <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-wider text-gray-400">
                  <span>学习率 (α)</span>
                  <span className="text-blue-600">{learningRate}</span>
                </div>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-lg font-black mb-4 flex items-center gap-2 text-gray-800">
              <span className="w-2 h-6 bg-purple-500 rounded-full"></span>
              已知数据生成
            </h2>
            <div className="space-y-4">
              <div>
                <div className="flex justify-between text-xs font-bold mb-1 text-gray-400">
                  <span>样本规模 (Total)</span>
                  <span className="text-purple-600">{sampleSize}</span>
                </div>
                <input type="range" min="50" max="600" step="10" value={sampleSize} onChange={e => setSampleSize(parseInt(e.target.value))} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-purple-600" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div className="p-3 bg-blue-50/50 rounded-xl border border-blue-100 text-center">
                  <div className="text-[10px] font-bold text-blue-400 mb-1">训练集 (70%)</div>
                  <div className="text-2xl font-black text-blue-700">{trainData.length}</div>
                </div>
                <div className="p-3 bg-indigo-50/50 rounded-xl border border-indigo-100 text-center">
                  <div className="text-[10px] font-bold text-indigo-400 mb-1">预测集 (30%)</div>
                  <div className="text-2xl font-black text-indigo-700">{testData.length}</div>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* 中央可视化区 */}
        <section className="lg:col-span-6 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow min-h-[420px] flex flex-col">
             <h2 className="text-lg font-black mb-4 flex items-center gap-2 text-gray-800">
              <span className="w-2 h-6 bg-indigo-500 rounded-full"></span>
              BP神经网络拓扑结构
            </h2>
            <div className="flex-grow">
              <NetworkGraph layers={layers} weights={network.weights} />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* 训练过程监控 */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[320px] flex flex-col">
              <h2 className="text-sm font-black mb-4 flex items-center justify-between text-gray-700">
                <div className="flex items-center gap-2">
                  <span className="w-2 h-5 bg-red-400 rounded-full"></span>
                  训练状态：收敛曲线
                </div>
                <div className="text-[10px] text-gray-400 font-mono">
                  LOSS: {currentLoss.toFixed(5)}
                </div>
              </h2>
              <div className="flex-grow">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={history}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                    <XAxis dataKey="epoch" hide />
                    <YAxis domain={[0, 'auto']} tick={{fontSize: 10, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
                    <Tooltip contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 20px -5px rgba(0,0,0,0.1)'}} />
                    <Line type="monotone" dataKey="loss" stroke="#ef4444" strokeWidth={3} dot={false} isAnimationActive={false} />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* 预测对比监控 */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[320px] flex flex-col">
              <h2 className="text-sm font-black mb-4 flex items-center justify-between text-gray-700">
                <div className="flex items-center gap-2">
                  <span className="w-2 h-5 bg-emerald-400 rounded-full"></span>
                  预测 vs 真实值 (预测集)
                </div>
                <button 
                  onClick={runEvaluation}
                  disabled={isPredicting || isTraining}
                  className={`text-[10px] px-2 py-1 rounded bg-blue-50 text-blue-600 border border-blue-100 hover:bg-blue-100 transition-colors ${isTraining ? 'opacity-50 cursor-not-allowed' : ''}`}
                >
                  {isPredicting ? '推理中...' : '开始作图'}
                </button>
              </h2>
              <div className="flex-grow relative">
                {testResults.length === 0 && !isPredicting && (
                  <div className="absolute inset-0 flex items-center justify-center text-center px-4 bg-gray-50/50 rounded-xl z-10 border border-dashed border-gray-200">
                    <p className="text-xs text-gray-400">点击右上角“开始作图”按钮<br/>使用当前参数对比预测结果</p>
                  </div>
                )}
                {isPredicting && (
                  <div className="absolute inset-0 flex items-center justify-center z-20 bg-white/80">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                  </div>
                )}
                <ResponsiveContainer width="100%" height="100%">
                  <ScatterChart margin={{ top: 10, right: 10, bottom: 20, left: -10 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f5f5f5" />
                    <XAxis type="number" dataKey="actual" name="真实值" domain={[0, 1]} tick={{fontSize: 10}} label={{ value: '真实', position: 'insideBottom', offset: -10, fontSize: 10, fill: '#94a3b8' }} />
                    <YAxis type="number" dataKey="predicted" name="预测值" domain={[0, 1]} tick={{fontSize: 10}} label={{ value: '预测', angle: -90, position: 'insideLeft', fontSize: 10, fill: '#94a3b8' }} />
                    <Tooltip cursor={{ strokeDasharray: '3 3' }} />
                    <Legend verticalAlign="top" height={30} iconType="circle" wrapperStyle={{fontSize: '10px'}} />
                    <ReferenceLine x={0} y={0} segment={[{ x: 0, y: 0 }, { x: 1, y: 1 }]} stroke="#cbd5e1" strokeDasharray="5 5" label={{ position: 'top', value: '完美线', fill: '#94a3b8', fontSize: 10 }} />
                    <Scatter name="模型预测点" data={testResults} fill="#3b82f6" fillOpacity={0.6} />
                  </ScatterChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </section>

        {/* 右侧 AI 诊断区 */}
        <section className="lg:col-span-3 flex flex-col">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow flex flex-col relative overflow-hidden">
            <div className="relative z-10 flex flex-col h-full">
              <h2 className="text-lg font-black mb-4 flex items-center justify-between text-gray-800">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 bg-blue-600 rounded-lg">
                    <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                  </div>
                  AI 模型诊断
                </div>
              </h2>

              <div className="flex-grow overflow-y-auto text-sm text-gray-600 leading-relaxed pr-2 custom-scrollbar">
                {aiInsight ? (
                  <div className="prose prose-sm prose-blue max-w-none">
                     <div dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>').replace(/### (.*?)<br\/>/g, '<h3 class="font-bold text-blue-700 mt-4 mb-1">$1</h3>') }} />
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-center py-10">
                    <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mb-4">
                      <svg className="w-8 h-8 text-blue-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 4a2 2 0 114 0v1a2 2 0 012 2v3a2 2 0 110 4V15a2 2 0 01-2 2v1a2 2 0 11-4 0v-1a2 2 0 01-2-2V9a2 2 0 012-2V4z"></path></svg>
                    </div>
                    <p className="text-gray-400 text-xs">点击下方按钮<br/>获取 AI 专家针对此架构的建议</p>
                  </div>
                )}
              </div>

              <button 
                onClick={handleGetInsight}
                disabled={isAiLoading || epoch === 0}
                className={`mt-4 w-full py-4 rounded-xl font-black shadow-lg transition-all ${
                  isAiLoading || epoch === 0 
                  ? 'bg-gray-100 text-gray-300 cursor-not-allowed' 
                  : 'bg-gradient-to-r from-blue-600 to-indigo-600 text-white hover:shadow-blue-200 active:scale-95'
                }`}
              >
                {isAiLoading ? (
                  <span className="flex items-center justify-center gap-2">
                    <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    正在诊断
