                        <YAxis type="number" dataKey="y" name="预测值" domain={[0, 1]} tick={{fontSize: 10}} label={{ value: '预测值', angle: -90, position: 'insideLeft', fontSize: 10, fill: '#94a3b8' }} />
                        <ReferenceLine x={0} y={0} segment={[{ x: 0, y: 0 }, { x: 1, y: 1 }]} stroke="#cbd5e1" strokeDasharray="5 5" label={{ position: 'top', value: '理想线', fill: '#94a3b8', fontSize: 10 }} />
                        <Scatter name="预测分布" data={testResults} fill="#3b82f6" fillOpacity={0.6} />
