                        <Scatter name="真实值" data={testResults.map(r => ({x: r.actualX, y: r.actualY}))} fill="#10b981" />
                        <Scatter name="预测值" data={testResults.map(r => ({x: r.predX, y: r.predY}))} fill="#3b82f6" />
                        {/* 强化对此：用红色粗实线连接真实点和预测点 */}
                        {testResults.map((r, i) => (
                          <ReferenceLine 
                            key={`err-line-${i}`} 
                            x={0} 
                            y={0} 
                            segment={[{ x: r.actualX, y: r.actualY }, { x: r.predX, y: r.predY }]} 
                            stroke="#ef4444" 
                            strokeWidth={3} 
                            strokeOpacity={0.6} 
                          />
                        ))}
                      </>
                    )}
                    <Tooltip cursor={{ strokeDasharray: '3 3' }} />
