                  </button>
                  <p className="text-[10px] text-gray-300">选定的密钥将安全存储于本地会话</p>
                </div>
              ) : (
                <>
                  <div className="px-3 py-2 bg-gray-50 rounded-xl flex items-center justify-between border border-gray-100">
                    <div className="flex flex-col">
                      <span className="text-[9px] font-bold text-gray-400 uppercase">当前已选引擎</span>
                      <span className={`text-[10px] font-black uppercase tracking-widest ${selectedModel === 'gemini' ? 'text-blue-600' : 'text-indigo-600'}`}>
                        {selectedModel === 'gemini' ? 'Gemini 2.5 Lite' : 'DeepSeek Base'}
                      </span>
                    </div>
                    <button onClick={handleSelectKey} className="text-[10px] text-gray-400 hover:text-blue-500 underline decoration-dotted underline-offset-2">重新配置密钥</button>
                  </div>

                  <div className="flex-grow overflow-y-auto text-sm text-gray-600 leading-relaxed pr-2 custom-scrollbar border-y border-gray-50 py-4">
                    {aiInsight ? (
                      <div className="prose prose-sm prose-blue max-w-none animate-in fade-in slide-in-from-bottom-2 duration-500">
                        <div dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>').replace(/### (.*?)<br\/>/g, '<h3 class="font-bold text-blue-700 mt-4 mb-1">$1</h3>') }} />
                      </div>
                    ) : (
                      <div className="h-full flex flex-col items-center justify-center text-center opacity-40">
                        <svg className="w-8 h-8 mb-2 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
                        <p className="text-xs">配置密钥并开启训练后<br/>点击下方按钮获取 AI 报告</p>
