  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

export type ModelType = 'gemini' | 'deepseek';

export const getAIInsights = async (config: any, stats: any, modelType: ModelType = 'gemini') => {
  // 必须在调用时实例化，以确保使用最新的 process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  /**
   * 模型映射逻辑：
   * gemini -> 'gemini-flash-lite-latest' (基础版)
   * deepseek -> 'gemini-3-flash-preview' (模拟基础版推理)
   */
  const targetModel = modelType === 'gemini' ? 'gemini-flash-lite-latest' : 'gemini-3-flash-preview';

  const prompt = `
    我正在运营一个BP神经网络可视化实验室。
    当前网络配置如下：
    - 输入层神经元：${config.layers[0]}
    - 隐藏层：${config.layers.slice(1, -1).join(', ') || '无'}
    - 输出层神经元：${config.layers[config.layers.length - 1]}
    - 学习率：${config.learningRate}

    目前的训练统计数据：
    - 已训练轮次 (Epoch)：${stats.epoch}
    - 当前损失值 (Loss)：${stats.loss.toFixed(6)}

    请作为一名深度学习专家，根据以上数据提供一份“AI专家洞察报告”。
    你的身份现在是：${modelType === 'gemini' ? 'Gemini 2.5 Lite 智能助手' : 'DeepSeek 基础版 (模拟)'}。

    报告要求：
    1. 评价当前网络结构的合理性（针对输入/输出维度的深度设计）。
    2. 对当前的损失值下降情况给出解释，并根据当前 epoch 给出具体的超参数优化建议。
    3. 用专业且具有洞察力的中文回答，控制在300字左右。
    4. 采用Markdown格式。
  `;

  try {
    const response = await ai.models.generateContent({
      model: targetModel,
      contents: prompt,
    });
    return response.text;
  } catch (error: any) {
    console.error("AI Error:", error);
    if (error?.message?.includes("Requested entity was not found.")) {
      return "ERROR_KEY_NOT_FOUND";
    }
    return `诊断过程中出现错误。请检查网络或重新配置 API 密钥。`;
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ScatterChart, Scatter, Legend, ReferenceLine } from 'recharts';
import { BPNetwork } from './services/bpEngine';
import NetworkGraph from './components/NetworkGraph';
import { getAIInsights, ModelType } from './services/geminiService';

const App: React.FC = () => {
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [sampleSize, setSampleSize] = useState(120);
  const [trainData, setTrainData] = useState<{ input: number[], output: number[] }[]>([]);
  const [testData, setTestData] = useState<{ input: number[], output: number[] }[]>([]);
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);
  const [testResults, setTestResults] = useState<any[]>([]);
  const [isPredicting, setIsPredicting] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  // AI 流程状态机: 1 (Key Input), 2 (Model Select), 3 (Ready/Result)
  const [aiStep, setAiStep] = useState<number>(1);
  const [selectedModel, setSelectedModel] = useState<ModelType>('gemini');

  const trainingRef = useRef<any>(null);

  // 初始化检查 API 密钥状态
  useEffect(() => {
    const checkKey = async () => {
      const exists = await window.aistudio.hasSelectedApiKey();
      if (exists) {
        setAiStep(2); // 如果已有密钥，直接进第二步：选择模型
      } else {
        setAiStep(1); // 否则必须从第一步开始
      }
    };
    checkKey();
  }, []);

  const handleStep1Complete = async () => {
    await window.aistudio.openSelectKey();
    // 触发弹窗后，根据规则假定成功，进入模型选择阶段
    setAiStep(2);
  };

  const handleStep2Complete = (model: ModelType) => {
    setSelectedModel(model);
    setAiStep(3); // 进入最终诊断阶段
  };

  const generateData = useCallback(() => {
    const inputDim = layers[0];
    const outputDim = layers[layers.length - 1];
    const newData = Array.from({ length: sampleSize }, () => {
      const input = Array.from({ length: inputDim }, () => Math.random() * 2 - 1);
      const output = Array.from({ length: outputDim }, (_, i) => {
        const factor = i === 0 ? 1 : -0.7;
        const base = Math.sin(input[0] * Math.PI) * Math.cos((input[1] || 1) * Math.PI * factor);
        return Math.max(0, Math.min(1, (base + (i * 0.2) + 1) / 2)); 
      });
      return { input, output };
    });

    const splitIdx = Math.floor(newData.length * 0.8);
    setTrainData(newData.slice(0, splitIdx));
    setTestData(newData.slice(splitIdx));

    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setTestResults([]);
    setAiInsight("");
    setIsTraining(false);
  }, [layers, learningRate, sampleSize]);

  const runEvaluation = useCallback(() => {
    if (!network || testData.length === 0) return;
    setIsPredicting(true);

    setTimeout(() => {
      const outputDim = layers[layers.length - 1];
      const results = testData.map((d) => {
        const activations = network.feedForward(d.input);
        const predicted = activations[activations.length - 1];
        if (outputDim === 1) {
          return { x: d.output[0], y: predicted[0] };
        } else {
          return {
            actualX: d.output[0],
            actualY: d.output[1],
            predX: predicted[0],
            predY: predicted[1]
          };
        }
      });
      setTestResults(results);
      setIsPredicting(false);
    }, 300);
  }, [network, testData, layers]);

  useEffect(() => {
    generateData();
  }, [layers[0], layers[2], sampleSize]);

  const trainStep = useCallback(() => {
    if (!network || trainData.length === 0) return;
    let totalLoss = 0;
    trainData.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });
    const avgLoss = totalLoss / trainData.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);
    if (epoch % 5 === 0) {
      setHistory(prev => [...prev.slice(-99), { epoch, loss: avgLoss }]);
    }
  }, [network, epoch, trainData]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 20);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handleGetInsight = async () => {
    setIsAiLoading(true);
    const result = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss }, selectedModel);

    if (result === "ERROR_KEY_NOT_FOUND") {
      setAiStep(1); // 密钥失效，滚回第一步
      setAiInsight("");
    } else {
      setAiInsight(result || "");
    }
    setIsAiLoading(false);
  };

  const outputDim = layers[layers.length - 1];

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6 font-sans select-none">
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div>
          <h1 className="text-3xl font-extrabold text-blue-600 tracking-tight text-center md:text-left">BP神经网络交互实验室</h1>
          <p className="text-gray-500 mt-1 italic text-center md:text-left">构建 · 训练 · 预测 · 洞察</p>
        </div>
        <div className="flex gap-3 mt-4 md:mt-0">
          <button onClick={() => setIsTraining(!isTraining)} className={`px-8 py-2 rounded-full font-bold transition-all shadow-md flex items-center gap-2 ${isTraining ? 'bg-amber-500 text-white hover:bg-amber-600' : 'bg-blue-600 text-white hover:bg-blue-700'}`}>
            {isTraining ? <><span className="w-2 h-2 bg-white rounded-full animate-ping"></span> 停止训练</> : <><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M4.5 3L15.5 10L4.5 17V3Z"/></svg> 开始训练</>}
          </button>
          <button onClick={generateData} className="px-8 py-2 rounded-full bg-white border border-gray-200 text-gray-700 font-bold hover:bg-gray-50 transition-all shadow-sm">重置环境</button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* 左侧控制栏 */}
        <section className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-lg font-black mb-4 flex items-center gap-2 text-gray-800"><span className="w-2 h-6 bg-blue-500 rounded-full"></span>架构设计</h2>
            <div className="space-y-5">
              <div>
                <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-wider text-gray-400"><span>输入层神经元</span><span className="text-blue-600">{layers[0]}</span></div>
                <input type="range" min="1" max="5" value={layers[0]} onChange={e => setLayers([parseInt(e.target.value), layers[1], layers[2]])} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div>
                <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-wider text-gray-400"><span>隐藏层神经元</span><span className="text-blue-600">{layers[1]}</span></div>
                <input type="range" min="1" max="12" value={layers[1]} onChange={e => setLayers([layers[0], parseInt(e.target.value), layers[2]])} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div>
                <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-wider text-gray-400"><span>输出层神经元 (1-2)</span><span className="text-blue-600">{layers[2]}</span></div>
                <input type="range" min="1" max="2" value={layers[2]} onChange={e => setLayers([layers[0], layers[1], parseInt(e.target.value)])} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div className="pt-2">
                <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-wider text-gray-400"><span>学习率 (LR)</span><span className="text-blue-600">{learningRate}</span></div>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-lg font-black mb-4 flex items-center gap-2 text-gray-800"><span className="w-2 h-6 bg-purple-500 rounded-full"></span>样本生成</h2>
            <div className="space-y-4">
              <div className="flex justify-between text-xs font-bold mb-1 text-gray-400"><span>总样本规模</span><span className="text-purple-600">{sampleSize}</span></div>
              <input type="range" min="50" max="600" step="10" value={sampleSize} onChange={e => setSampleSize(parseInt(e.target.value))} className="w-full h-1.5 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-purple-600" />
              <div className="grid grid-cols-2 gap-3">
                <div className="p-3 bg-blue-50/50 rounded-xl border border-blue-100 text-center"><div className="text-[10px] font-bold text-blue-400 mb-1">训练集 (80%)</div><div className="text-2xl font-black text-blue-700">{trainData.length}</div></div>
                <div className="p-3 bg-indigo-50/50 rounded-xl border border-indigo-100 text-center"><div className="text-[10px] font-bold text-indigo-400 mb-1">预测集 (20%)</div><div className="text-2xl font-black text-indigo-700">{testData.length}</div></div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow">
            <h2 className="text-lg font-black mb-4 flex items-center gap-2 text-gray-800"><span className="w-2 h-6 bg-amber-400 rounded-full"></span>神经网络知识</h2>
            <div className="space-y-4 text-xs leading-relaxed text-gray-600 overflow-y-auto max-h-[200px] custom-scrollbar pr-1">
              <section><h3 className="font-bold text-gray-800 mb-1">神经思想</h3><p>模拟大脑神经元的“连接主义”，通过加权求和与激活函数（Sigmoid）进行非线性信息处理。</p></section>
              <section><h3 className="font-bold text-gray-800 mb-1">发展历程</h3><p>从1958年感知机，到1986年BP反向传播，奠定了今日深度学习之基。</p></section>
            </div>
          </div>
        </section>

        {/* 中间可视化栏 */}
        <section className="lg:col-span-6 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow min-h-[420px] flex flex-col">
             <h2 className="text-lg font-black mb-4 flex items-center gap-2 text-gray-800"><span className="w-2 h-6 bg-indigo-500 rounded-full"></span>实时拓扑可视化 (编号 1-N)</h2>
            <div className="flex-grow"><NetworkGraph layers={layers} weights={network.weights} /></div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[300px] flex flex-col">
              <h2 className="text-sm font-black mb-4 flex items-center justify-between text-gray-700">
                <div className="flex items-center gap-2"><span className="w-2 h-5 bg-red-400 rounded-full"></span>损失收敛 (MSE)</div>
                <div className="text-[10px] text-gray-400 font-mono">LOSS: {currentLoss.toFixed(5)}</div>
              </h2>
              <div className="flex-grow">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={history}><CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" /><XAxis dataKey="epoch" hide /><YAxis domain={[0, 'auto']} tick={{fontSize: 10, fill: '#94a3b8'}} axisLine={false} tickLine={false} /><Tooltip contentStyle={{borderRadius: '12px', border: 'none'}} /><Line type="monotone" dataKey="loss" stroke="#ef4444" strokeWidth={3} dot={false} isAnimationActive={false} /></LineChart>
                </ResponsiveContainer>
              </div>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[300px] flex flex-col">
              <h2 className="text-sm font-black mb-4 flex items-center justify-between text-gray-700">
                <div className="flex items-center gap-2"><span className="w-2 h-5 bg-emerald-400 rounded-full"></span>预测 vs 真实值</div>
                <button onClick={runEvaluation} disabled={isPredicting || isTraining} className="text-[10px] px-2 py-1 rounded bg-blue-50 text-blue-600 border border-blue-100 hover:bg-blue-100 transition-colors">开始预测</button>
              </h2>
              <div className="flex-grow">
                <ResponsiveContainer width="100%" height="100%">
                  <ScatterChart margin={{ top: 10, right: 10, bottom: 20, left: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f5f5f5" />
                    {outputDim === 1 ? (
                      <>
                        <XAxis type="number" dataKey="x" name="真实值" domain={[0, 1]} tick={{fontSize: 10}} />
                        <YAxis type="number" dataKey="y" name="预测值" domain={[0, 1]} tick={{fontSize: 10}} />
                        <ReferenceLine segment={[{ x: 0, y: 0 }, { x: 1, y: 1 }]} stroke="#6366f1" strokeWidth={3} />
                        <Scatter name="预测点" data={testResults} fill="#3b82f6" fillOpacity={0.6} />
                      </>
                    ) : (
                      <>
                        <XAxis type="number" dataKey="x" domain={[0, 1]} tick={{fontSize: 10}} />
