                <div className="flex items-center gap-3 mb-5">
                  <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black ${aiStep === 3 ? 'bg-emerald-600 text-white' : 'bg-gray-200 text-gray-500'}`}>3</div>
                  <span className="text-[11px] font-bold text-gray-700 uppercase tracking-widest">第三步：专家诊断报告</span>
                </div>

                {aiStep === 3 ? (
                  <div className="flex flex-col h-full animate-in fade-in duration-700">
                    <div className="flex-grow overflow-y-auto text-[11px] leading-relaxed text-gray-600 custom-scrollbar mb-5 pr-2">
                      {aiInsight ? (
                        <div className="prose prose-sm prose-emerald max-w-none">
                          <div dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>').replace(/### (.*?)<br\/>/g, '<h3 class="font-bold text-emerald-800 mt-4 mb-1 uppercase tracking-wider">$1</h3>') }} />
                        </div>
                      ) : (
                        <div className="h-full flex flex-col items-center justify-center opacity-40 italic text-center py-10 space-y-3">
                          <svg className="w-10 h-10 text-gray-300 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                          <p>数据链路已就绪<br/>点击下方按钮由 {selectedModel === 'gemini' ? 'Gemini' : 'DeepSeek'} 启动分析</p>
                        </div>
                      )}
                    </div>
                    <button 
                      onClick={handleGetInsight}
                      disabled={isAiLoading || epoch === 0}
                      className={`w-full py-4 rounded-2xl font-black text-xs text-white shadow-lg transition-all ${isAiLoading || epoch === 0 ? 'bg-gray-200 text-gray-400 cursor-not-allowed' : 'bg-gradient-to-r from-emerald-600 to-teal-600 hover:shadow-emerald-200 hover:scale-[1.02] active:scale-95'}`}
                    >
                      {isAiLoading ? (
