export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ScatterChart, Scatter, Legend, ReferenceLine } from 'recharts';
import { BPNetwork } from './services/bpEngine';
import NetworkGraph from './components/NetworkGraph';
import { getAIInsights, ModelType } from './services/geminiService';

const App: React.FC = () => {
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [sampleSize, setSampleSize] = useState(120);
  const [trainData, setTrainData] = useState<{ input: number[], output: number[] }[]>([]);
  const [testData, setTestData] = useState<{ input: number[], output: number[] }[]>([]);
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);
  const [testResults, setTestResults] = useState<any[]>([]);
  const [isPredicting, setIsPredicting] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  // AI 状态管理
  const [hasApiKey, setHasApiKey] = useState(false);
  const [selectedModel, setSelectedModel] = useState<ModelType>('gemini');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const trainingRef = useRef<any>(null);

  // 检测密钥状态
  const checkKeyStatus = async () => {
    const exists = await window.aistudio.hasSelectedApiKey();
    setHasApiKey(exists);
    return exists;
  };

  useEffect(() => {
    checkKeyStatus();
  }, []);

  const handleOpenKeyConfig = async () => {
    await window.aistudio.openSelectKey();
    // 竞态处理：触发后即认为尝试配置
    const exists = await checkKeyStatus();
    if (!exists) setHasApiKey(true); // 强制乐观更新以允许模型选择
  };

  const generateData = useCallback(() => {
    const inputDim = layers[0];
    const outputDim = layers[layers.length - 1];
    const newData = Array.from({ length: sampleSize }, () => {
      const input = Array.from({ length: inputDim }, () => Math.random() * 2 - 1);
      const output = Array.from({ length: outputDim }, (_, i) => {
        const factor = i === 0 ? 1 : -0.7;
        const base = Math.sin(input[0] * Math.PI) * Math.cos((input[1] || 1) * Math.PI * factor);
        return Math.max(0, Math.min(1, (base + (i * 0.2) + 1) / 2)); 
      });
      return { input, output };
    });

    const splitIdx = Math.floor(newData.length * 0.8);
    setTrainData(newData.slice(0, splitIdx));
    setTestData(newData.slice(splitIdx));

    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setTestResults([]);
    setAiInsight("");
    setIsTraining(false);
  }, [layers, learningRate, sampleSize]);

  const runEvaluation = useCallback(() => {
    if (!network || testData.length === 0) return;
    setIsPredicting(true);

    setTimeout(() => {
      const outputDim = layers[layers.length - 1];
      const results = testData.map((d) => {
        const activations = network.feedForward(d.input);
        const predicted = activations[activations.length - 1];
        if (outputDim === 1) {
          return { x: d.output[0], y: predicted[0] };
        } else {
          return {
            actualX: d.output[0],
            actualY: d.output[1],
            predX: predicted[0],
            predY: predicted[1]
          };
        }
      });
      setTestResults(results);
      setIsPredicting(false);
    }, 300);
  }, [network, testData, layers]);

  useEffect(() => {
    generateData();
  }, [layers[0], layers[2], sampleSize]);

  const trainStep = useCallback(() => {
    if (!network || trainData.length === 0) return;
    let totalLoss = 0;
    trainData.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });
    const avgLoss = totalLoss / trainData.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);
    if (epoch % 5 === 0) {
      setHistory(prev => [...prev.slice(-99), { epoch, loss: avgLoss }]);
    }
  }, [network, epoch, trainData]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 20);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handleGetInsight = async () => {
    if (!hasApiKey) {
      setIsSettingsOpen(true);
      return;
    }
    setIsAiLoading(true);
    const result = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss }, selectedModel);

    if (result === "ERROR_KEY_NOT_FOUND") {
      setHasApiKey(false);
      setIsSettingsOpen(true);
      setAiInsight("");
    } else {
      setAiInsight(result || "");
    }
    setIsAiLoading(false);
  };

  const outputDim = layers[layers.length - 1];

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6 font-sans select-none">
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200">
            <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z"></path></svg>
          </div>
          <div>
            <h1 className="text-3xl font-extrabold text-blue-600 tracking-tight">NeuralLab 实验室</h1>
            <p className="text-gray-400 text-xs mt-0.5 font-medium tracking-wide italic">BP NEURAL NETWORK INTERACTIVE PLATFORM</p>
          </div>
        </div>
        <div className="flex gap-3 mt-4 md:mt-0">
          <button onClick={() => setIsTraining(!isTraining)} className={`px-8 py-2.5 rounded-full font-bold transition-all shadow-md flex items-center gap-2 ${isTraining ? 'bg-amber-500 text-white hover:bg-amber-600 scale-105' : 'bg-blue-600 text-white hover:bg-blue-700'}`}>
            {isTraining ? <><span className="w-2 h-2 bg-white rounded-full animate-ping"></span> 训练中</> : <><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M4.5 3L15.5 10L4.5 17V3Z"/></svg> 启动训练</>}
          </button>
          <button onClick={generateData} className="px-6 py-2.5 rounded-full bg-white border border-gray-200 text-gray-600 font-bold hover:bg-gray-50 transition-all">重构环境</button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* 左侧控制栏 */}
        <section className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-sm font-black mb-5 flex items-center gap-2 text-gray-800 uppercase tracking-widest"><span className="w-1.5 h-4 bg-blue-500 rounded-full"></span> 架构设计 (Neurons)</h2>
            <div className="space-y-6">
              {[
                { label: '输入层', key: 0, max: 5 },
                { label: '隐藏层', key: 1, max: 12 },
                { label: '输出层', key: 2, max: 2, min: 1 }
              ].map(layer => (
                <div key={layer.key}>
                  <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-gray-400"><span>{layer.label}</span><span className="text-blue-600 font-mono text-sm">{layers[layer.key]}</span></div>
                  <input type="range" min={layer.min || 1} max={layer.max} value={layers[layer.key]} onChange={e => {
                    const newLayers = [...layers];
                    newLayers[layer.key] = parseInt(e.target.value);
                    setLayers(newLayers);
                  }} className="w-full h-1 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
                </div>
              ))}
              <div className="pt-2">
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-gray-400"><span>学习率 (Alpha)</span><span className="text-blue-600 font-mono text-sm">{learningRate}</span></div>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full h-1 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-sm font-black mb-5 flex items-center gap-2 text-gray-800 uppercase tracking-widest"><span className="w-1.5 h-4 bg-purple-500 rounded-full"></span> 数据样本控制</h2>
            <div className="space-y-4">
              <div className="flex justify-between text-[10px] font-bold mb-1.5 text-gray-400 uppercase tracking-wider"><span>样本总量</span><span className="text-purple-600 font-mono text-sm">{sampleSize}</span></div>
              <input type="range" min="50" max="600" step="10" value={sampleSize} onChange={e => setSampleSize(parseInt(e.target.value))} className="w-full h-1 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-purple-600" />
              <div className="grid grid-cols-2 gap-3 pt-2">
                <div className="p-3 bg-blue-50/30 rounded-xl border border-blue-100 text-center"><div className="text-[9px] font-bold text-blue-400 mb-0.5 uppercase">Train</div><div className="text-xl font-black text-blue-700">{trainData.length}</div></div>
                <div className="p-3 bg-indigo-50/30 rounded-xl border border-indigo-100 text-center"><div className="text-[9px] font-bold text-indigo-400 mb-0.5 uppercase">Test</div><div className="text-xl font-black text-indigo-700">{testData.length}</div></div>
              </div>
            </div>
          </div>

          {/* 神经思想模块：淡白色极简风格 */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow border-l-4 border-l-blue-200">
            <h2 className="text-sm font-black mb-4 flex items-center gap-2 uppercase tracking-widest text-gray-500"><span className="w-1.5 h-4 bg-blue-100 rounded-full"></span> 神经思想模块</h2>
            <div className="space-y-5 text-[11px] leading-relaxed text-gray-400 overflow-y-auto max-h-[220px] custom-scrollbar pr-1">
              <section><h3 className="font-bold text-gray-600 mb-1 flex items-center gap-1"><span className="w-1 h-1 bg-blue-400 rounded-full"></span> 连接主义</h3><p>模拟生物大脑神经元之间的突触连接，通过权重 $(w)$ 与偏置 $(b)$ 的自适应调整，实现从感知到认知的飞跃。</p></section>
              <section><h3 className="font-bold text-gray-600 mb-1 flex items-center gap-1"><span className="w-1 h-1 bg-blue-400 rounded-full"></span> 反向传播</h3><p>核心思想是利用微积分的链式法则，将输出层产生的误差逆向逐层分配，以此优化整个网络的决策边界。</p></section>
            </div>
          </div>
        </section>

        {/* 中间可视化栏 */}
        <section className="lg:col-span-6 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow min-h-[420px] flex flex-col relative overflow-hidden">
             <h2 className="text-sm font-black mb-4 flex items-center gap-2 text-gray-800 uppercase tracking-widest"><span className="w-1.5 h-4 bg-indigo-500 rounded-full"></span> 动态网络拓扑 (1-Indexed)</h2>
            <div className="flex-grow"><NetworkGraph layers={layers} weights={network.weights} /></div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[300px] flex flex-col">
              <h2 className="text-xs font-black mb-4 flex items-center justify-between text-gray-700 uppercase tracking-wider">
                <div className="flex items-center gap-2"><span className="w-1.5 h-4 bg-red-400 rounded-full"></span> 损失收敛曲线</div>
                <div className="text-[10px] text-gray-400 font-mono">MSE: {currentLoss.toFixed(5)}</div>
              </h2>
              <div className="flex-grow">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={history}><CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" /><XAxis dataKey="epoch" hide /><YAxis domain={[0, 'auto']} tick={{fontSize: 9, fill: '#94a3b8'}} axisLine={false} tickLine={false} /><Tooltip contentStyle={{borderRadius: '12px', border: 'none', fontSize: '10px'}} /><Line type="monotone" dataKey="loss" stroke="#ef4444" strokeWidth={2.5} dot={false} isAnimationActive={false} /></LineChart>
