                  <ScatterChart margin={{ top: 10, right: 10, bottom: 20, left: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f5f5f5" />
                    {outputDim === 1 ? (
                      <>
                        <XAxis type="number" dataKey="x" name="Actual" domain={[0, 1]} tick={{fontSize: 9}} />
                        <YAxis type="number" dataKey="y" name="Pred" domain={[0, 1]} tick={{fontSize: 9}} />
                        <ReferenceLine segment={[{ x: 0, y: 0 }, { x: 1, y: 1 }]} stroke="#6366f1" strokeWidth={2} strokeDasharray="4 4" />
