                        <Scatter name="真实" data={testResults.map(r => ({x: r.actualX, y: r.actualY}))} fill="#10b981" shape="circle" />
                        <Scatter name="预测" data={testResults.map(r => ({x: r.predX, y: r.predY}))} fill="#3b82f6" shape="cross" />
                        {testResults.map((r, i) => (
                          <ReferenceLine key={i} segment={[{ x: r.actualX, y: r.actualY }, { x: r.predX, y: r.predY }]} stroke="#ef4444" strokeWidth={1.5} strokeOpacity={0.6} />
