                      </button>
                      <p className="text-[9px] text-gray-400 italic">必须先点击此按钮在对话框中输入密钥</p>
                    </div>

                    {/* Step 2: Model Selection (Enabled after Key) */}
                    <div className={`space-y-2 transition-opacity ${!hasApiKey ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
                      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">2. 选择对应大模型</label>
                      <div className="grid grid-cols-1 gap-2">
                        <button 
                          onClick={() => setSelectedModel('gemini')}
                          className={`w-full p-3 rounded-xl border text-left flex items-center justify-between transition-all ${selectedModel === 'gemini' ? 'border-blue-500 bg-blue-50/50 shadow-sm ring-1 ring-blue-500' : 'border-gray-100 hover:border-blue-200'}`}
                        >
                          <div>
                            <div className="text-[11px] font-black text-gray-800">Gemini 2.5 Lite</div>
                            <div className="text-[9px] text-gray-400 uppercase">基础轻量版</div>
