                          {selectedModel === 'gemini' && <div className="w-2 h-2 bg-blue-600 rounded-full animate-pulse"></div>}
                        </button>
                        <button 
                          onClick={() => setSelectedModel('deepseek')}
                          className={`w-full p-3 rounded-xl border text-left flex items-center justify-between transition-all ${selectedModel === 'deepseek' ? 'border-indigo-500 bg-indigo-50/50 shadow-sm ring-1 ring-indigo-500' : 'border-gray-100 hover:border-indigo-200'}`}
                        >
                          <div>
                            <div className="text-[11px] font-black text-gray-800">DeepSeek (模拟)</div>
                            <div className="text-[9px] text-gray-400 uppercase">稳健基础版</div>
                          </div>
                          {selectedModel === 'deepseek' && <div className="w-2 h-2 bg-indigo-600 rounded-full animate-pulse"></div>}
                        </button>
                      </div>
                    </div>

                    <button 
                      onClick={() => setIsSettingsOpen(false)}
                      disabled={!hasApiKey}
                      className="w-full mt-4 py-2 text-[10px] font-black text-gray-400 hover:text-indigo-600 transition-colors uppercase tracking-widest"
                    >
                      完成配置并返回
                    </button>
                  </div>
                </div>
              )}

              {/* 报告主体展示区域 */}
              <div className="flex-grow flex flex-col p-2">
                <div className="flex-grow overflow-y-auto text-[11px] leading-relaxed text-gray-500 custom-scrollbar mb-4 pr-1">
                  {aiInsight ? (
                    <div className="prose prose-sm prose-indigo max-w-none animate-in fade-in slide-in-from-bottom-2 duration-500">
                      <div dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>').replace(/### (.*?)<br\/>/g, '<h3 class="font-bold text-indigo-700 mt-4 mb-1 uppercase tracking-wider">$1</h3>') }} />
                    </div>
                  ) : (
                    <div className="h-full flex flex-col items-center justify-center opacity-30 italic text-center py-20 space-y-4">
                      <svg className="w-12 h-12 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                      <div>
                        <p className="font-bold text-xs mb-1">等待诊断生成</p>
                        <p className="text-[10px]">请点击右上角齿轮配置模型<br/>并确保网络已有训练数据</p>
                      </div>
                    </div>
                  )}
                </div>

                <div className="mt-auto space-y-3">
                  <div className="flex items-center justify-between px-2">
                    <span className="text-[9px] font-bold text-gray-300 uppercase tracking-widest">当前引擎状态</span>
                    <span className={`text-[9px] font-black uppercase ${hasApiKey ? 'text-green-500' : 'text-amber-500'}`}>
                      {hasApiKey ? `${selectedModel === 'gemini' ? 'Gemini 2.5' : 'DeepSeek'} 在线` : '未配置密钥'}
                    </span>
                  </div>
                  <button 
                    onClick={handleGetInsight}
                    disabled={isAiLoading || epoch === 0 || !hasApiKey}
                    className={`w-full py-4 rounded-2xl font-black text-xs text-white shadow-xl transition-all ${isAiLoading || epoch === 0 || !hasApiKey ? 'bg-gray-100 text-gray-300 cursor-not-allowed shadow-none' : 'bg-gradient-to-br from-indigo-600 to-blue-600 hover:scale-[1.02] active:scale-95 shadow-indigo-100'}`}
                  >
                    {isAiLoading ? (
                      <div className="flex items-center justify-center gap-2">
                        <div className="w-3.5 h-3.5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                        报告生成中...
                      </div>
                    ) : !hasApiKey ? '需先配置密钥' : epoch === 0 ? '请先启动网络训练' : '立即生成解答报告'}
