import { GoogleGenAI } from "@google/genai";

export type ModelType = 'gemini' | 'deepseek';

export const getAIInsights = async (config: any, stats: any, modelType: ModelType = 'gemini', manualApiKey?: string) => {
  // 优先使用手动输入的 Key，如果没有则回退到环境变量 process.env.API_KEY
  const apiKeyToUse = manualApiKey || process.env.API_KEY;

  if (!apiKeyToUse) {
    return "ERROR_KEY_NOT_FOUND";
  }

  const ai = new GoogleGenAI({ apiKey: apiKeyToUse });

  /**
   * 模型映射逻辑：
   * gemini -> 'gemini-flash-lite-latest' (Gemini 2.5 Lite)
   * deepseek -> 'gemini-3-flash-preview' (作为 DeepSeek 基础版的模拟引擎)
   */
  const targetModel = modelType === 'gemini' ? 'gemini-flash-lite-latest' : 'gemini-3-flash-preview';

  const prompt = `
    你是一名深度学习专家。请针对以下 BP 神经网络实验室的当前状态提供简明、专业的诊断报告。

    网络配置：
    - 层级结构 (Neurons per layer)：${config.layers.join(' -> ')}
    - 学习率 (Learning Rate)：${config.learningRate}

    训练数据：
    - 已执行轮次 (Epochs)：${stats.epoch}
    - 当前均方误差 (Current Loss)：${stats.loss.toFixed(6)}

    诊断要求：
    1. 评估当前网络拓扑结构与输入/输出维度的匹配度。
    2. 分析损失收敛趋势（例如：收敛过慢、收敛曲线震荡原因）。
    3. 给出 1-2 条具体的超参数（如学习率、神经元数）调整建议。

    请使用标准 Markdown 格式回答，保持在 250 字左右，语言风格大方专业。
  `;

  try {
    const response = await ai.models.generateContent({
      model: targetModel,
      contents: prompt,
    });
    return response.text;
  } catch (error: any) {
    console.error("AI Error:", error);
    if (error?.message?.includes("API_KEY_INVALID") || error?.message?.includes("key not found")) {
      return "ERROR_KEY_NOT_FOUND";
    }
    return `诊断模块未能响应，请检查密钥是否正确及网络连接。`;
  }
};

