import { getAIInsights, ModelType } from './services/geminiService';

const App: React.FC = () => {
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [sampleSize, setSampleSize] = useState(120);
  const [trainData, setTrainData] = useState<{ input: number[], output: number[] }[]>([]);
  const [testData, setTestData] = useState<{ input: number[], output: number[] }[]>([]);
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);
  const [testResults, setTestResults] = useState<any[]>([]);
  const [isPredicting, setIsPredicting] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedModel, setSelectedModel] = useState<ModelType>('gemini');

  const trainingRef = useRef<any>(null);

  const generateData = useCallback(() => {
    const inputDim = layers[0];
    const outputDim = layers[layers.length - 1];
    const newData = Array.from({ length: sampleSize }, () => {
      const input = Array.from({ length: inputDim }, () => Math.random() * 2 - 1);
      const output = Array.from({ length: outputDim }, (_, i) => {
        const factor = i === 0 ? 1 : -0.7;
        const base = Math.sin(input[0] * Math.PI) * Math.cos((input[1] || 1) * Math.PI * factor);
        return Math.max(0, Math.min(1, (base + (i * 0.2) + 1) / 2)); 
      });
      return { input, output };
    });

    const splitIdx = Math.floor(newData.length * 0.8);
    setTrainData(newData.slice(0, splitIdx));
    setTestData(newData.slice(splitIdx));

    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setTestResults([]);
    setAiInsight("");
    setIsTraining(false);
  }, [layers, learningRate, sampleSize]);

  const runEvaluation = useCallback(() => {
    if (!network || testData.length === 0) return;
    setIsPredicting(true);

    setTimeout(() => {
      const outputDim = layers[layers.length - 1];
      const results = testData.map((d) => {
        const activations = network.feedForward(d.input);
        const predicted = activations[activations.length - 1];
        if (outputDim === 1) {
          return { x: d.output[0], y: predicted[0] };
        } else {
          return {
            actualX: d.output[0],
            actualY: d.output[1],
            predX: predicted[0],
            predY: predicted[1]
          };
        }
      });
      setTestResults(results);
      setIsPredicting(false);
    }, 300);
  }, [network, testData, layers]);

  useEffect(() => {
    generateData();
  }, [layers[0], layers[2], sampleSize, generateData]);

  const trainStep = useCallback(() => {
    if (!network || trainData.length === 0) return;
    let totalLoss = 0;
    trainData.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });
    const avgLoss = totalLoss / trainData.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);
    if (epoch % 5 === 0) {
      setHistory(prev => [...prev.slice(-99), { epoch, loss: avgLoss }]);
    }
  }, [network, epoch, trainData]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 20);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handleGetInsight = async () => {
    setIsAiLoading(true);
    const result = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss }, selectedModel);

    if (result === "ERROR_KEY_NOT_FOUND") {
      alert("未检测到 API Key，请确保环境变量中已配置 API_KEY。");
      setAiInsight("");
    } else {
      setAiInsight(result || "");
    }
    setIsAiLoading(false);
  };

  const outputDim = layers[layers.length - 1];

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6 font-sans select-none">
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200 text-white">
            <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H9a2 2 0 00-2 2v10a2 2 0 002 2z" />
            </svg>
          </div>
          <div>
            <h1 className="text-2xl font-black text-gray-800 tracking-tight">BP Neural Lab</h1>
            <p className="text-xs text-gray-400 font-medium">深度学习模型在线实验室</p>
          </div>
        </div>

        <div className="flex items-center gap-3 mt-4 md:mt-0">
          <select 
            value={selectedModel}
            onChange={(e) => setSelectedModel(e.target.value as ModelType)}
            className="px-3 py-2 bg-gray-100 border-none rounded-lg text-sm font-semibold text-gray-600 focus:ring-2 focus:ring-blue-500"
          >
            <option value="gemini">Gemini 3 Flash</option>
            <option value="deepseek">Gemini 3 Pro</option>
          </select>
          <button
            onClick={handleGetInsight}
            disabled={isAiLoading || epoch < 10}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold text-sm transition-all shadow-md ${
              isAiLoading ? 'bg-gray-200 text-gray-400 cursor-not-allowed' : 'bg-gradient-to-r from-purple-600 to-blue-600 text-white hover:scale-105 active:scale-95'
            }`}
          >
            {isAiLoading ? '分析中...' : 'AI 专家诊断'}
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* 控制面板 */}
        <aside className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h3 className="text-sm font-bold text-gray-500 mb-6 uppercase tracking-wider">核心配置</h3>

            <div className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-gray-400 mb-2">隐藏层神经元 ({layers[1]})</label>
                <input 
                  type="range" min="1" max="12" step="1" 
                  value={layers[1]} 
                  onChange={(e) => {
                    const val = parseInt(e.target.value);
                    setLayers([layers[0], val, layers[2]]);
                  }}
                  className="w-full h-1.5 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                />
              </div>

              <div>
                <label className="block text-xs font-bold text-gray-400 mb-2">学习率 ({learningRate})</label>
                <input 
                  type="range" min="0.01" max="1" step="0.01" 
                  value={learningRate} 
                  onChange={(e) => setLearningRate(parseFloat(e.target.value))}
                  className="w-full h-1.5 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                />
              </div>

              <div>
                <label className="block text-xs font-bold text-gray-400 mb-2">样本规模 ({sampleSize})</label>
                <select 
                  value={sampleSize} 
                  onChange={(e) => setSampleSize(parseInt(e.target.value))}
                  className="w-full p-2 bg-gray-50 border border-gray-100 rounded-lg text-sm font-medium focus:ring-2 focus:ring-blue-500"
                >
                  <option value={60}>60 (快速训练)</option>
                  <option value={120}>120 (标准训练)</option>
                  <option value={300}>300 (大量数据)</option>
                </select>
              </div>
            </div>

            <div className="mt-8 flex flex-col gap-3">
              <button
                onClick={() => setIsTraining(!isTraining)}
                className={`w-full py-3 rounded-xl font-bold transition-all shadow-lg ${
                  isTraining ? 'bg-orange-500 text-white shadow-orange-100' : 'bg-blue-600 text-white shadow-blue-100'
                }`}
              >
                {isTraining ? '暂停训练' : '开始训练'}
              </button>
              <button
                onClick={generateData}
                className="w-full py-3 bg-gray-50 text-gray-600 rounded-xl font-bold border border-gray-100 hover:bg-gray-100 transition-all"
              >
                重置网络
              </button>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-1">
            <h3 className="text-sm font-bold text-gray-500 mb-4 uppercase tracking-wider">训练状态</h3>
            <div className="grid grid-cols-2 gap-4">
              <div className="p-3 bg-blue-50 rounded-xl">
                <p className="text-[10px] text-blue-400 font-bold uppercase">Epochs</p>
                <p className="text-xl font-black text-blue-700">{epoch}</p>
              </div>
              <div className="p-3 bg-purple-50 rounded-xl">
                <p className="text-[10px] text-purple-400 font-bold uppercase">Loss</p>
                <p className="text-xl font-black text-purple-700">{currentLoss.toFixed(4)}</p>
              </div>
            </div>
          </div>
        </aside>

        {/* 主视窗 */}
        <main className="lg:col-span-9 flex flex-col gap-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-[400px]">
            <NetworkGraph layers={layers} weights={network.weights} />
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest">损失收敛曲线</h3>
                {history.length > 0 && <span className="text-[10px] text-green-500 font-bold">实时更新中</span>}
              </div>
              <div className="h-[320px]">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={history}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                    <XAxis dataKey="epoch" hide />
                    <YAxis domain={[0, 'auto']} tick={{fontSize: 10, fill: '#9ca3af'}} />
                    <Tooltip 
                      contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.05)'}}
                    />
                    <Line type="monotone" dataKey="loss" stroke="#3b82f6" strokeWidth={3} dot={false} animationDuration={300} />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest">模型评估结果 (测试集)</h3>
              <button 
                onClick={runEvaluation}
                disabled={isPredicting}
                className="text-xs font-bold text-blue-600 hover:text-blue-700 px-3 py-1 bg-blue-50 rounded-full"
              >
                {isPredicting ? '运算中...' : '重新评估'}
              </button>
            </div>

            <div className="h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <ScatterChart margin={{ top: 20, right: 20, bottom: 20, left: 20 }}>
                  <CartesianGrid stroke="#f0f0f0" />
                  <XAxis type="number" dataKey="x" name="Actual" label={{ value: '真实值', position: 'bottom', fontSize: 10 }} hide={outputDim > 1} />
                  <YAxis type="number" dataKey="y" name="Predicted" label={{ value: '预测值', angle: -90, position: 'insideLeft', fontSize: 10 }} hide={outputDim > 1} />
                  <Tooltip cursor={{ strokeDasharray: '3 3' }} />
                  {outputDim === 1 ? (
                    <>
                      <ReferenceLine segment={[{ x: 0, y: 0 }, { x: 1, y: 1 }]} stroke="#9ca3af" strokeDasharray="5 5" />
                      <Scatter name="预测分布" data={testResults} fill="#3b82f6" />
                    </>
                  ) : (
                    <Scatter name="多维数据不予散点展示" data={[]} />
                  )}
                </ScatterChart>
              </ResponsiveContainer>
              {outputDim > 1 && (
                <div className="flex items-center justify-center h-full text-gray-400 text-sm font-medium">
                  多输出维度暂不支持 2D 散点图可视化
                </div>
              )}
            </div>
          </div>

          {aiInsight && (
            <div className="bg-gradient-to-br from-indigo-50 to-blue-50 p-6 rounded-2xl border border-blue-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center gap-2 mb-4">
                <div className="w-6 h-6 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
                  <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M11 3a1 1 0 10-2 0v1a1 1 0 102 0V3zM15.657 5.757a1 1 0 00-1.414-1.414l-.707.707a1 1 0 001.414 1.414l.707-.707zM18 10a1 1 0 01-1 1h-1a1 1 0 110-2h1a1 1 0 011 1zM5.05 6.464A1 1 0 106.464 5.05l-.707-.707a1 1 0 00-1.414 1.414l.707.707zM5 10a1 1 0 01-1 1H3a1 1 0 110-2h1a1 1 0 011 1zM8 16v-1a1 1 0 112 0v1a1 1 0 11-2 0zM13.536 14.95a1 1 0 011.414 0l.707.707a1 1 0 11-1.414 1.414l-.707-.707a1 1 0 010-1.414zM15.657 14.243a1 1 0 00-1.414-1.414l-.707.707a1 1 0 001.414 1.414l.707-.707z" /></svg>
                </div>
                <h3 className="text-sm font-bold text-indigo-900 uppercase">AI 专家诊断报告</h3>
              </div>
              <div className="prose prose-sm max-w-none text-indigo-800 font-medium leading-relaxed">
                {aiInsight.split('\n').map((line, i) => <p key={i}>{line}</p>)}
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ScatterChart, Scatter, Legend, ReferenceLine } from 'recharts';
import { BPNetwork } from './services/bpEngine';
import NetworkGraph from './components/NetworkGraph';
import { getAIInsights, ModelType } from './services/geminiService';

const App: React.FC = () => {
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [sampleSize, setSampleSize] = useState(120);
  const [trainData, setTrainData] = useState<{ input: number[], output: number[] }[]>([]);
  const [testData, setTestData] = useState<{ input: number[], output: number[] }[]>([]);
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);
  const [testResults, setTestResults] = useState<any[]>([]);
  const [isPredicting, setIsPredicting] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  // AI 状态管理
  const [hasApiKey, setHasApiKey] = useState(false);
  const [selectedModel, setSelectedModel] = useState<ModelType>('gemini');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const trainingRef = useRef<any>(null);

  // 初始化检查 API 密钥状态
  useEffect(() => {
    const checkKey = async () => {
      const exists = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(exists);
    };
    checkKey();
  }, []);

  const handleOpenConfigDialog = async () => {
    // 调用平台提供的密钥接收对话框（这是符合环境规范的唯一手工输入方式）
    await window.aistudio.openSelectKey();
    // 乐观更新状态，假设用户操作成功
    setHasApiKey(true);
  };

  const generateData = useCallback(() => {
    const inputDim = layers[0];
    const outputDim = layers[layers.length - 1];
    const newData = Array.from({ length: sampleSize }, () => {
      const input = Array.from({ length: inputDim }, () => Math.random() * 2 - 1);
      const output = Array.from({ length: outputDim }, (_, i) => {
        const factor = i === 0 ? 1 : -0.7;
        const base = Math.sin(input[0] * Math.PI) * Math.cos((input[1] || 1) * Math.PI * factor);
        return Math.max(0, Math.min(1, (base + (i * 0.2) + 1) / 2)); 
      });
      return { input, output };
    });

    const splitIdx = Math.floor(newData.length * 0.8);
    setTrainData(newData.slice(0, splitIdx));
    setTestData(newData.slice(splitIdx));

    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setTestResults([]);
    setAiInsight("");
    setIsTraining(false);
  }, [layers, learningRate, sampleSize]);

  const runEvaluation = useCallback(() => {
    if (!network || testData.length === 0) return;
    setIsPredicting(true);

    setTimeout(() => {
      const outputDim = layers[layers.length - 1];
      const results = testData.map((d) => {
        const activations = network.feedForward(d.input);
        const predicted = activations[activations.length - 1];
        if (outputDim === 1) {
          return { x: d.output[0], y: predicted[0] };
        } else {
          return {
            actualX: d.output[0],
            actualY: d.output[1],
            predX: predicted[0],
            predY: predicted[1]
          };
        }
      });
      setTestResults(results);
      setIsPredicting(false);
    }, 300);
  }, [network, testData, layers]);

  useEffect(() => {
    generateData();
  }, [layers[0], layers[2], sampleSize]);

  const trainStep = useCallback(() => {
    if (!network || trainData.length === 0) return;
    let totalLoss = 0;
    trainData.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });
    const avgLoss = totalLoss / trainData.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);
    if (epoch % 5 === 0) {
      setHistory(prev => [...prev.slice(-99), { epoch, loss: avgLoss }]);
    }
  }, [network, epoch, trainData]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 20);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handleGetInsight = async () => {
    if (!hasApiKey) {
      setIsSettingsOpen(true);
      return;
    }
    setIsAiLoading(true);
    const result = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss }, selectedModel);

    if (result === "ERROR_KEY_NOT_FOUND") {
      setHasApiKey(false);
      setIsSettingsOpen(true);
      setAiInsight("");
    } else {
      setAiInsight(result || "");
    }
    setIsAiLoading(false);
  };

  const outputDim = layers[layers.length - 1];

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6 font-sans select-none">
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200">
            <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z"></path></svg>
          </div>
          <div>
            <h1 className="text-3xl font-extrabold text-blue-600 tracking-tight">NeuralLab</h1>
            <p className="text-gray-400 text-[10px] mt-0.5 font-bold uppercase tracking-[0.2em]">BP Neural Network Laboratory</p>
          </div>
        </div>
        <div className="flex gap-3 mt-4 md:mt-0">
          <button onClick={() => setIsTraining(!isTraining)} className={`px-8 py-2.5 rounded-full font-bold transition-all shadow-md flex items-center gap-2 ${isTraining ? 'bg-amber-500 text-white hover:bg-amber-600 scale-105' : 'bg-blue-600 text-white hover:bg-blue-700'}`}>
            {isTraining ? <><span className="w-2 h-2 bg-white rounded-full animate-ping"></span> 训练中</> : <><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M4.5 3L15.5 10L4.5 17V3Z"/></svg> 启动训练</>}
          </button>
          <button onClick={generateData} className="px-6 py-2.5 rounded-full bg-white border border-gray-200 text-gray-600 font-bold hover:bg-gray-50 transition-all">重构环境</button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* 左侧控制栏 */}
        <section className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-sm font-black mb-5 flex items-center gap-2 text-gray-800 uppercase tracking-widest"><span className="w-1.5 h-4 bg-blue-500 rounded-full"></span> 架构设计 (Neurons)</h2>
            <div className="space-y-6">
              {[
                { label: '输入层', key: 0, max: 5 },
                { label: '隐藏层', key: 1, max: 12 },
                { label: '输出层', key: 2, max: 2, min: 1 }
              ].map(layer => (
                <div key={layer.key}>
                  <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-gray-400"><span>{layer.label}</span><span className="text-blue-600 font-mono text-sm">{layers[layer.key]}</span></div>
                  <input type="range" min={layer.min || 1} max={layer.max} value={layers[layer.key]} onChange={e => {
                    const newLayers = [...layers];
                    newLayers[layer.key] = parseInt(e.target.value);
                    setLayers(newLayers);
                  }} className="w-full h-1 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
                </div>
              ))}
              <div className="pt-2">
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-gray-400"><span>学习率 (Alpha)</span><span className="text-blue-600 font-mono text-sm">{learningRate}</span></div>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full h-1 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
