              <div className="pt-2">
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-400"><span>学习率 (Alpha)</span><span className="text-blue-600 font-mono text-sm">{learningRate}</span></div>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full h-1 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
            </div>
