import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface NetworkGraphProps {
  layers: number[];
  weights: number[][][];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ layers, weights }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;
    const margin = 60; 

    // 获取权重最大绝对值用于归一化
    let maxAbsWeight = 0;
    weights.forEach(layer => layer.forEach(neuron => neuron.forEach(w => {
      const absW = Math.abs(w);
      if (absW > maxAbsWeight) maxAbsWeight = absW;
    })));
    if (maxAbsWeight === 0) maxAbsWeight = 1;

    // 定义统一的有向箭头 Marker
    const defs = svg.append("defs");

    defs.append("marker")
      .attr("id", "arrow-head")
      .attr("viewBox", "0 -5 10 10")
      .attr("refX", 26) 
      .attr("refY", 0)
      .attr("markerWidth", 5)
      .attr("markerHeight", 5)
      .attr("orient", "auto")
      .append("path")
      .attr("d", "M0,-5L10,0L0,5")
      .attr("fill", "#000000");

    const layerSpacing = (width - 2 * margin) / (layers.length - 1 || 1);

    const nodes: any[] = [];
    const nodeMap: { [key: string]: any } = {};

    // 绘制层级标识
    layers.forEach((_, lIdx) => {
      const x = margin + lIdx * layerSpacing;
      let label = "隐藏层";
      let colorClass = "fill-slate-400";
      if (lIdx === 0) {
        label = "输入层";
        colorClass = "fill-blue-500";
      } else if (lIdx === layers.length - 1) {
        label = "输出层";
        colorClass = "fill-emerald-500";
      }

      svg.append("text")
        .attr("x", x)
        .attr("y", 25)
        .attr("text-anchor", "middle")
        .attr("font-size", "11px")
        .attr("font-weight", "900")
        .attr("class", `${colorClass} uppercase tracking-[0.2em]`)
        .text(label);
    });

    // 创建节点数据
    layers.forEach((count, lIdx) => {
      const x = margin + lIdx * layerSpacing;
      const vertSpacing = (height - 2 * margin) / (count || 1);
      const startY = margin + (height - 2 * margin - (count - 1) * vertSpacing) / 2;

      for (let i = 0; i < count; i++) {
        const id = `l${lIdx}n${i}`;
        const node = { id, x, y: startY + i * vertSpacing, layer: lIdx, displayIndex: i + 1 };
        nodes.push(node);
        nodeMap[id] = node;
      }
    });

    // 创建边数据
    const edges: any[] = [];
    for (let l = 0; l < weights.length; l++) {
      for (let j = 0; j < weights[l].length; j++) {
        for (let k = 0; k < weights[l][j].length; k++) {
          if (nodeMap[`l${l}n${k}`] && nodeMap[`l${l+1}n${j}`]) {
            edges.push({
              source: nodeMap[`l${l}n${k}`],
              target: nodeMap[`l${l+1}n${j}`],
              weight: weights[l][j][k]
            });
          }
        }
      }
    }

    // 绘制权重动态连线
    svg.append("g")
      .selectAll("line")
      .data(edges)
      .enter()
      .append("line")
      .attr("x1", d => d.source.x)
      .attr("y1", d => d.source.y)
      .attr("x2", d => d.target.x)
      .attr("y2", d => d.target.y)
      .attr("stroke", "#000000")
      // 粗细与不透明度随权重绝对值动态变化，基准粗度 3.0
      .attr("stroke-width", d => (Math.abs(d.weight) / maxAbsWeight) * 4.0 + 1.0)
      .attr("opacity", d => (Math.abs(d.weight) / maxAbsWeight) * 0.7 + 0.1)
      .attr("marker-end", "url(#arrow-head)");

    // 绘制神经元节点
    const nodeGroups = svg.append("g")
      .selectAll("g")
      .data(nodes)
      .enter()
      .append("g");

    nodeGroups.append("circle")
      .attr("cx", d => d.x)
      .attr("cy", d => d.y)
      .attr("r", 14)
      .attr("fill", "white")
      .attr("stroke", d => {
        if (d.layer === 0) return "#3b82f6";
        if (d.layer === layers.length - 1) return "#10b981";
        return "#6366f1";
      })
      .attr("stroke-width", 2);

    nodeGroups.append("text")
      .attr("x", d => d.x)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "10px")
      .attr("font-weight", "bold")
      .attr("fill", "#1e40af")
      .text(d => d.displayIndex);

    // 添加图例
    const legend = svg.append("g")
      .attr("transform", `translate(${width - 120}, ${height - 50})`);

    legend.append("text")
      .attr("font-size", "9px")
      .attr("font-weight", "bold")
      .attr("fill", "#94a3b8")
      .attr("class", "uppercase tracking-widest")
      .text("权重可视化");

    // 弱权重示例
    legend.append("line")
      .attr("x1", 0).attr("y1", 15).attr("x2", 30).attr("y2", 15)
      .attr("stroke", "#000000").attr("stroke-width", 1.0).attr("opacity", 0.2);
    legend.append("text").attr("x", 35).attr("y", 18).attr("font-size", "8px").attr("fill", "#cbd5e1").text("弱权重");

    // 强权重示例
    legend.append("line")
      .attr("x1", 0).attr("y1", 30).attr("x2", 30).attr("y2", 30)
      .attr("stroke", "#000000").attr("stroke-width", 4.0).attr("opacity", 0.8);
    legend.append("text").attr("x", 35).attr("y", 33).attr("font-size", "8px").attr("fill", "#64748b").text("强权重");

  }, [layers, weights]);

  return (
    <div className="w-full h-full bg-white rounded-xl shadow-inner border border-blue-50 overflow-hidden relative">
      <div className="absolute bottom-2 left-2 text-[10px] text-slate-300 font-bold uppercase tracking-widest pointer-events-none">实时拓扑有向图</div>
      <svg ref={svgRef} className="w-full h-full" />
    </div>
  );
};

