                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-400"><span>收敛阈值 (Stop at)</span><span className="text-red-500 font-mono text-sm">{stopThreshold.toFixed(4)}</span></div>
