                <p className="text-slate-500 leading-relaxed">
                  BP 神经网络是一种按误差反向传播算法训练的多层前向网络，通过梯度下降法自发调整权重以最小化输出误差。
                </p>
              </section>
              <section className="border-l-2 border-blue-100 pl-4 py-1">
                <h3 className="font-bold text-slate-600 mb-2 italic">前向传播算法</h3>
                <div className="font-mono bg-white/70 p-3 rounded-xl text-blue-700/70 border border-blue-50 shadow-inner">
                  a<sub>j</sub> = σ( Σ w<sub>jk</sub> a<sub>k</sub> + b<sub>j</sub> )
                </div>
              </section>
              <section className="border-l-2 border-red-100 pl-4 py-1">
                <h3 className="font-bold text-slate-600 mb-2 italic">反向传播迭代</h3>
                <div className="space-y-2 font-mono bg-white/70 p-3 rounded-xl text-red-700/70 border border-red-50 shadow-inner">
                  <p>δ<sub>j</sub> = ∂E / ∂z<sub>j</sub></p>
                  <p>Δw<sub>jk</sub> = -η (δ<sub>j</sub> · a<sub>k</sub>)</p>
                </div>
              </section>
            </div>
          </div>
        </section>

        {/* 中间可视化栏 */}
        <section className="lg:col-span-6 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow min-h-[420px] flex flex-col relative overflow-hidden">
