            <div className="flex-grow"><NetworkGraph layers={layers} weights={network.weights} /></div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[300px] flex flex-col">
              <h2 className="text-xs font-black mb-4 flex items-center justify-between text-slate-700 uppercase tracking-wider">
                <div className="flex items-center gap-2"><span className="w-1.5 h-4 bg-red-400 rounded-full"></span> 损失收敛曲线</div>
                <div className="text-[10px] text-slate-400 font-mono">MSE: {currentLoss.toFixed(5)}</div>
              </h2>
              <div className="flex-grow">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={history}><CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" /><XAxis dataKey="epoch" hide /><YAxis domain={[0, 'auto']} tick={{fontSize: 9, fill: '#94a3b8'}} axisLine={false} tickLine={false} /><Tooltip contentStyle={{borderRadius: '12px', border: 'none', fontSize: '10px'}} /><Line type="monotone" dataKey="loss" stroke="#ef4444" strokeWidth={2.5} dot={false} isAnimationActive={false} /></LineChart>
                </ResponsiveContainer>
              </div>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[300px] flex flex-col">
              <h2 className="text-xs font-black mb-4 flex items-center justify-between text-slate-700 uppercase tracking-wider">
                <div className="flex items-center gap-2"><span className="w-1.5 h-4 bg-emerald-400 rounded-full"></span> 模型预测评估</div>
                <button onClick={runEvaluation} disabled={isPredicting || isTraining} className="text-[9px] px-2.5 py-1 rounded-full bg-blue-50 text-blue-600 border border-blue-100 hover:bg-blue-100 transition-colors">执行预测</button>
              </h2>
              <div className="flex-grow relative">
                {currentLoss <= stopThreshold && epoch > 0 && (
                  <div className="absolute top-2 right-2 z-10 bg-emerald-50 text-emerald-600 text-[8px] px-2 py-0.5 rounded-full font-black border border-emerald-200 animate-bounce">
                    模型已收敛
                  </div>
                )}
                <ResponsiveContainer width="100%" height="100%">
                  <ScatterChart margin={{ top: 20, right: 20, bottom: 25, left: 10 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f5f5f5" />
                    {outputDim === 1 ? (
                      <>
                        <XAxis type="number" dataKey="x" domain={[0, 1]} tick={{fontSize: 9}}>
                          <Label value="真实值" position="insideBottom" offset={-15} style={{fontSize: '9px', fontWeight: 'bold', fill: '#64748b'}} />
                        </XAxis>
                        <YAxis type="number" dataKey="y" domain={[0, 1]} tick={{fontSize: 9}}>
                          <Label value="预测值" angle={-90} position="insideLeft" offset={10} style={{fontSize: '9px', fontWeight: 'bold', fill: '#64748b'}} />
                        </YAxis>
                        <ReferenceLine segment={[{ x: 0, y: 0 }, { x: 1, y: 1 }]} stroke="#6366f1" strokeWidth={2} strokeDasharray="4 4" />
                        <Scatter name="预测点" data={testResults} fill="#3b82f6" fillOpacity={0.6} />
                      </>
                    ) : (
                      <>
                        <XAxis type="number" dataKey="x" domain={[0, 1]} tick={{fontSize: 9}}>
                           <Label value="输出 1" position="insideBottom" offset={-15} style={{fontSize: '9px', fontWeight: 'bold', fill: '#64748b'}} />
                        </XAxis>
                        <YAxis type="number" dataKey="y" domain={[0, 1]} tick={{fontSize: 9}}>
                           <Label value="输出 2" angle={-90} position="insideLeft" offset={10} style={{fontSize: '9px', fontWeight: 'bold', fill: '#64748b'}} />
                        </YAxis>
                        <Legend verticalAlign="top" height={36} iconType="circle" wrapperStyle={{fontSize: '9px', top: -10}} />
                        <Scatter name="真实目标" data={testResults.map(r => ({x: r.actualX, y: r.actualY}))} fill="#10b981" />
                        <Scatter name="预测结果" data={testResults.map(r => ({x: r.predX, y: r.predY}))} fill="#3b82f6" shape="cross" />
                        {testResults.map((r, i) => (
                           <ReferenceLine key={i} segment={[{ x: r.actualX, y: r.actualY }, { x: r.predX, y: r.predY }]} stroke="#ef4444" strokeWidth={1} strokeOpacity={0.3} />
                        ))}
                      </>
                    )}
                    <Tooltip cursor={{ strokeDasharray: '3 3' }} />
                  </ScatterChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </section>

        {/* 右侧 AI 诊断栏 */}
        <section className="lg:col-span-3 flex flex-col relative">
          <div className="bg-white p-6 rounded-2xl shadow-xl shadow-slate-200/50 flex-grow flex flex-col border border-slate-100 overflow-hidden relative">
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-600 rounded-lg shadow-md shadow-indigo-100">
                  <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                </div>
                <h2 className="text-lg font-black text-slate-800 tracking-tight">AI 模型诊断中心</h2>
              </div>
              <button 
                onClick={() => setIsSettingsOpen(true)} 
                className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-all"
                title="诊断设置"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
              </button>
            </div>

            <div className="flex-grow flex flex-col">
              <div className="flex-grow overflow-y-auto text-[11px] leading-relaxed text-slate-500 custom-scrollbar mb-5 pr-1">
                {aiInsight ? (
                  <div className="prose prose-sm prose-indigo max-w-none animate-in fade-in slide-in-from-bottom-2 duration-500">
                    <div dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>').replace(/### (.*?)<br\/>/g, '<h3 class="font-bold text-indigo-700 mt-4 mb-1 uppercase tracking-wider">$1</h3>') }} />
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center opacity-40 italic text-center py-20">
                    <svg className="w-12 h-12 mb-4 text-slate-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"></path></svg>
                    <p className="text-xs font-bold">待研判诊断报告</p>
                    <p className="text-[10px] mt-1">请点击右上角齿轮<br/>手工录入 API 密钥后启动诊断</p>
                  </div>
                )}
              </div>

              <div className="mt-auto pt-4 border-t border-slate-50">
                <div className="flex items-center justify-between mb-3 px-1">
                  <span className="text-[9px] font-bold text-slate-300 uppercase tracking-widest">诊断引擎：{manualKey ? getModelLabel() : '等待密钥'}</span>
                  {manualKey && <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse shadow-sm shadow-green-200"></div>}
