import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface NetworkGraphProps {
  layers: number[];
  weights: number[][][];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ layers, weights }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;
    const margin = 80; 

    // 获取权重最大绝对值用于归一化
    let maxAbsWeight = 0;
    weights.forEach(layer => layer.forEach(neuron => neuron.forEach(w => {
      const absW = Math.abs(w);
      if (absW > maxAbsWeight) maxAbsWeight = absW;
    })));
    if (maxAbsWeight === 0) maxAbsWeight = 1;

    // 定义滤镜和箭头
    const defs = svg.append("defs");

    // 1. 节点外部阴影
    const filter = defs.append("filter")
      .attr("id", "drop-shadow")
      .attr("x", "-50%")
      .attr("y", "-50%")
      .attr("width", "200%")
      .attr("height", "200%");
    filter.append("feDropShadow")
      .attr("dx", "0")
      .attr("dy", "2")
      .attr("stdDeviation", "3")
      .attr("flood-color", "#000000")
      .attr("flood-opacity", "0.15");

    // 2. 节点内部渐变 (根据层级)
    const createGradient = (id: string, color1: string, color2: string) => {
      const grad = defs.append("linearGradient")
        .attr("id", id)
        .attr("x1", "0%").attr("y1", "0%")
        .attr("x2", "0%").attr("y2", "100%");
      grad.append("stop").attr("offset", "0%").attr("stop-color", color1);
      grad.append("stop").attr("offset", "100%").attr("stop-color", color2);
    };
    createGradient("grad-input", "#eff6ff", "#dbeafe");
    createGradient("grad-hidden", "#f5f3ff", "#ede9fe");
    createGradient("grad-output", "#ecfdf5", "#d1fae5");

    // 3. 有向箭头
    defs.append("marker")
      .attr("id", "arrow-head")
      .attr("viewBox", "0 -5 10 10")
      .attr("refX", 32) // 避开加大的神经元模型
      .attr("refY", 0)
      .attr("markerWidth", 5)
      .attr("markerHeight", 5)
      .attr("orient", "auto")
      .append("path")
      .attr("d", "M0,-5L10,0L0,5")
      .attr("fill", "#64748b");

    const layerSpacing = (width - 2 * margin) / (layers.length - 1 || 1);

    const nodes: any[] = [];
    const nodeMap: { [key: string]: any } = {};

    // 绘制层级标题
    layers.forEach((_, lIdx) => {
      const x = margin + lIdx * layerSpacing;
      let label = "隐藏层 (Hidden)";
      let colorClass = "fill-indigo-700";
      if (lIdx === 0) {
        label = "输入层 (Input)";
        colorClass = "fill-blue-700";
      } else if (lIdx === layers.length - 1) {
        label = "输出层 (Output)";
        colorClass = "fill-emerald-800";
      }

      svg.append("text")
        .attr("x", x)
        .attr("y", 40)
        .attr("text-anchor", "middle")
        .attr("font-size", "11px")
        .attr("font-weight", "900")
        .attr("class", `${colorClass} uppercase tracking-[0.3em]`)
        .text(label);
    });

    // 创建节点坐标
    layers.forEach((count, lIdx) => {
      const x = margin + lIdx * layerSpacing;
      const vertSpacing = (height - 2 * margin) / (count || 1);
      const startY = margin + (height - 2 * margin - (count - 1) * vertSpacing) / 2;

      for (let i = 0; i < count; i++) {
        const id = `l${lIdx}n${i}`;
        const node = { id, x, y: startY + i * vertSpacing, layer: lIdx, index: i + 1 };
        nodes.push(node);
        nodeMap[id] = node;
      }
    });

    // 绘制权重连接线
    const edges: any[] = [];
    for (let l = 0; l < weights.length; l++) {
      for (let j = 0; j < weights[l].length; j++) {
        for (let k = 0; k < weights[l][j].length; k++) {
          if (nodeMap[`l${l}n${k}`] && nodeMap[`l${l+1}n${j}`]) {
            edges.push({
              source: nodeMap[`l${l}n${k}`],
              target: nodeMap[`l${l+1}n${j}`],
              weight: weights[l][j][k]
            });
          }
        }
      }
    }

    svg.append("g")
      .selectAll("line")
      .data(edges)
      .enter()
      .append("line")
      .attr("x1", d => d.source.x)
      .attr("y1", d => d.source.y)
      .attr("x2", d => d.target.x)
      .attr("y2", d => d.target.y)
      .attr("stroke", d => d.weight > 0 ? "#2563eb" : "#dc2626")
      .attr("stroke-width", d => (Math.abs(d.weight) / maxAbsWeight) * 4 + 0.6)
      .attr("opacity", d => (Math.abs(d.weight) / maxAbsWeight) * 0.7 + 0.2)
      .attr("marker-end", "url(#arrow-head)");

    // 绘制高级神经元模型 (Σ | σ)
    const nodeGroups = svg.append("g")
      .selectAll("g")
      .data(nodes)
      .enter()
      .append("g")
      .attr("filter", "url(#drop-shadow)");

    // 背景胶囊体/圆形
    const radius = 22;
    nodeGroups.append("circle")
      .attr("cx", d => d.x)
      .attr("cy", d => d.y)
      .attr("r", radius)
      .attr("fill", d => {
        if (d.layer === 0) return "url(#grad-input)";
        if (d.layer === layers.length - 1) return "url(#grad-output)";
        return "url(#grad-hidden)";
      })
      .attr("stroke", d => {
        if (d.layer === 0) return "#2563eb";
        if (d.layer === layers.length - 1) return "#059669";
        return "#4f46e5";
      })
      .attr("stroke-width", 2);

    // 中间分割线
    nodeGroups.append("line")
      .attr("x1", d => d.x).attr("y1", d => d.y - radius + 5)
      .attr("x2", d => d.x).attr("y2", d => d.y + radius - 5)
      .attr("stroke", d => {
        if (d.layer === 0) return "#60a5fa";
        if (d.layer === layers.length - 1) return "#34d399";
        return "#818cf8";
      })
      .attr("stroke-width", 1.2)
      .attr("stroke-dasharray", "2 1");

    // 左侧 Σ (求和符号)
    nodeGroups.append("text")
      .attr("x", d => d.x - 8)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px")
      .attr("font-family", "serif")
      .attr("font-weight", "900")
      .attr("fill", d => d.layer === 0 ? "#1e3a8a" : d.layer === layers.length - 1 ? "#064e3b" : "#312e81")
      .text("Σ");

    // 右侧 σ (激活符号)
    nodeGroups.append("text")
      .attr("x", d => d.x + 8)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px")
      .attr("font-family", "serif")
      .attr("font-weight", "900")
      .attr("fill", d => d.layer === 0 ? "#1e3a8a" : d.layer === layers.length - 1 ? "#064e3b" : "#312e81")
      .text("σ");

    // 顶部序号 Badge
    const badge = nodeGroups.append("g")
      .attr("transform", d => `translate(${d.x}, ${d.y - radius - 2})`);

    badge.append("rect")
      .attr("x", -10).attr("y", -8)
      .attr("width", 20).attr("height", 10)
      .attr("rx", 4)
      .attr("fill", d => {
        if (d.layer === 0) return "#1d4ed8";
        if (d.layer === layers.length - 1) return "#047857";
        return "#4338ca";
      });

    badge.append("text")
      .attr("text-anchor", "middle")
      .attr("y", -1)
      .attr("font-size", "7.5px")
      .attr("font-weight", "black")
      .attr("fill", "white")
      .text(d => `N${d.index}`);

    // 图例说明
    const legend = svg.append("g")
      .attr("transform", `translate(${width - 160}, ${height - 110})`);

    legend.append("rect")
      .attr("width", 145).attr("height", 95)
      .attr("rx", 12)
      .attr("fill", "white")
      .attr("fill-opacity", 0.95)
      .attr("stroke", "#e2e8f0")
      .attr("stroke-width", 1.5);

    legend.append("text")
      .attr("x", 12).attr("y", 22)
      .attr("font-size", "10px")
      .attr("font-weight", "black")
      .attr("fill", "#1e293b")
      .attr("class", "uppercase tracking-widest")
      .text("神经网络图例");

    // 权重示例
    legend.append("line")
      .attr("x1", 12).attr("y1", 38).attr("x2", 42).attr("y2", 38)
      .attr("stroke", "#2563eb").attr("stroke-width", 3.5);
    legend.append("text").attr("x", 48).attr("y", 41).attr("font-size", "9px").attr("font-weight", "bold").attr("fill", "#475569").text("正权重 (兴奋)");

    legend.append("line")
      .attr("x1", 12).attr("y1", 53).attr("x2", 42).attr("y2", 53)
      .attr("stroke", "#dc2626").attr("stroke-width", 3.5);
    legend.append("text").attr("x", 48).attr("y", 56).attr("font-size", "9px").attr("font-weight", "bold").attr("fill", "#475569").text("负权重 (抑制)");

    // 模型示例
    legend.append("circle").attr("cx", 27).attr("cy", 75).attr("r", 10).attr("fill", "#f1f5f9").attr("stroke", "#94a3b8").attr("stroke-width", 1.5);
    legend.append("text").attr("x", 48).attr("y", 78).attr("font-size", "9px").attr("font-weight", "bold").attr("fill", "#475569").text("Σ 求和 | σ 激活");

  }, [layers, weights]);

  return (
    <div className="w-full h-full bg-white rounded-xl shadow-inner border border-blue-100 overflow-hidden relative">
      <div className="absolute top-4 left-4 flex items-center gap-2">
         <div className="w-2.5 h-2.5 bg-blue-600 rounded-full animate-pulse shadow-sm shadow-blue-200"></div>
         <span className="text-[11px] text-slate-700 font-black uppercase tracking-widest pointer-events-none">实时物理神经元模拟</span>
      </div>
      <svg ref={svgRef} className="w-full h-full" />
    </div>
  );
};

export default NetworkGraph;

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface NetworkGraphProps {
  layers: number[];
  weights: number[][][];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ layers, weights }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;
    // 增加顶部边距以容纳标签并创建“空行”感
    const marginTop = 100; 
    const marginBottom = 80;
    const marginSide = 80;

    // 获取权重最大绝对值用于归一化
    let maxAbsWeight = 0;
    weights.forEach(layer => layer.forEach(neuron => neuron.forEach(w => {
      const absW = Math.abs(w);
      if (absW > maxAbsWeight) maxAbsWeight = absW;
    })));
    if (maxAbsWeight === 0) maxAbsWeight = 1;

    // 定义滤镜和箭头
    const defs = svg.append("defs");

    // 1. 节点外部阴影
    const filter = defs.append("filter")
      .attr("id", "drop-shadow")
      .attr("x", "-50%")
      .attr("y", "-50%")
      .attr("width", "200%")
      .attr("height", "200%");
    filter.append("feDropShadow")
      .attr("dx", "0")
      .attr("dy", "2")
      .attr("stdDeviation", "3")
      .attr("flood-color", "#000000")
      .attr("flood-opacity", "0.15");

    // 2. 节点内部渐变 (根据层级)
    const createGradient = (id: string, color1: string, color2: string) => {
      const grad = defs.append("linearGradient")
        .attr("id", id)
        .attr("x1", "0%").attr("y1", "0%")
        .attr("x2", "0%").attr("y2", "100%");
      grad.append("stop").attr("offset", "0%").attr("stop-color", color1);
      grad.append("stop").attr("offset", "100%").attr("stop-color", color2);
    };
    createGradient("grad-input", "#eff6ff", "#dbeafe");
    createGradient("grad-hidden", "#f5f3ff", "#ede9fe");
    createGradient("grad-output", "#ecfdf5", "#d1fae5");

    // 3. 有向箭头
    defs.append("marker")
      .attr("id", "arrow-head")
      .attr("viewBox", "0 -5 10 10")
      .attr("refX", 32)
      .attr("refY", 0)
      .attr("markerWidth", 5)
      .attr("markerHeight", 5)
      .attr("orient", "auto")
      .append("path")
      .attr("d", "M0,-5L10,0L0,5")
      .attr("fill", "#475569");

    const layerSpacing = (width - 2 * marginSide) / (layers.length - 1 || 1);

    const nodes: any[] = [];
    const nodeMap: { [key: string]: any } = {};

    // 绘制层级标题 - 将 y 坐标下移至 65，并在顶部增加间距
    layers.forEach((_, lIdx) => {
      const x = marginSide + lIdx * layerSpacing;
      let label = "隐藏层 (Hidden)";
      let colorClass = "fill-indigo-900";
      if (lIdx === 0) {
        label = "输入层 (Input)";
        colorClass = "fill-blue-900";
      } else if (lIdx === layers.length - 1) {
        label = "输出层 (Output)";
        colorClass = "fill-emerald-900";
      }

      svg.append("text")
        .attr("x", x)
        .attr("y", 65) // 下移标题位置，与顶部标签拉开距离
        .attr("text-anchor", "middle")
        .attr("font-size", "11px")
        .attr("font-weight", "900")
        .attr("class", `${colorClass} uppercase tracking-[0.3em]`)
        .text(label);
    });

    // 创建节点坐标
    layers.forEach((count, lIdx) => {
      const x = marginSide + lIdx * layerSpacing;
      const vertSpacing = (height - marginTop - marginBottom) / (count || 1);
      const startY = marginTop + (height - marginTop - marginBottom - (count - 1) * vertSpacing) / 2;

      for (let i = 0; i < count; i++) {
        const id = `l${lIdx}n${i}`;
        const node = { id, x, y: startY + i * vertSpacing, layer: lIdx, index: i + 1 };
        nodes.push(node);
        nodeMap[id] = node;
      }
    });

    // 绘制权重连接线
    const edges: any[] = [];
    for (let l = 0; l < weights.length; l++) {
      for (let j = 0; j < weights[l].length; j++) {
        for (let k = 0; k < weights[l][j].length; k++) {
          if (nodeMap[`l${l}n${k}`] && nodeMap[`l${l+1}n${j}`]) {
            edges.push({
              source: nodeMap[`l${l}n${k}`],
              target: nodeMap[`l${l+1}n${j}`],
              weight: weights[l][j][k]
            });
          }
        }
      }
    }

    svg.append("g")
      .selectAll("line")
      .data(edges)
      .enter()
      .append("line")
      .attr("x1", d => d.source.x)
      .attr("y1", d => d.source.y)
      .attr("x2", d => d.target.x)
      .attr("y2", d => d.target.y)
      .attr("stroke", d => d.weight > 0 ? "#1e40af" : "#b91c1c")
      .attr("stroke-width", d => (Math.abs(d.weight) / maxAbsWeight) * 4 + 0.6)
      .attr("opacity", d => (Math.abs(d.weight) / maxAbsWeight) * 0.7 + 0.2)
      .attr("marker-end", "url(#arrow-head)");

    // 绘制高级神经元模型 (Σ | σ)
    const nodeGroups = svg.append("g")
      .selectAll("g")
      .data(nodes)
      .enter()
      .append("g")
      .attr("filter", "url(#drop-shadow)");

    const radius = 22;
    nodeGroups.append("circle")
      .attr("cx", d => d.x)
      .attr("cy", d => d.y)
      .attr("r", radius)
      .attr("fill", d => {
        if (d.layer === 0) return "url(#grad-input)";
        if (d.layer === layers.length - 1) return "url(#grad-output)";
        return "url(#grad-hidden)";
      })
      .attr("stroke", d => {
        if (d.layer === 0) return "#1e40af";
        if (d.layer === layers.length - 1) return "#065f46";
        return "#3730a3";
      })
      .attr("stroke-width", 2);

    nodeGroups.append("line")
      .attr("x1", d => d.x).attr("y1", d => d.y - radius + 5)
      .attr("x2", d => d.x).attr("y2", d => d.y + radius - 5)
      .attr("stroke", d => {
        if (d.layer === 0) return "#3b82f6";
        if (d.layer === layers.length - 1) return "#10b981";
        return "#6366f1";
      })
      .attr("stroke-width", 1.2)
      .attr("stroke-dasharray", "2 1");

    nodeGroups.append("text")
      .attr("x", d => d.x - 8)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px")
      .attr("font-family", "serif")
      .attr("font-weight", "900")
      .attr("fill", d => d.layer === 0 ? "#1e3a8a" : d.layer === layers.length - 1 ? "#064e3b" : "#312e81")
      .text("Σ");

    nodeGroups.append("text")
      .attr("x", d => d.x + 8)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px")
      .attr("font-family", "serif")
      .attr("font-weight", "900")
      .attr("fill", d => d.layer === 0 ? "#1e3a8a" : d.layer === layers.length - 1 ? "#064e3b" : "#312e81")
      .text("σ");

    const badge = nodeGroups.append("g")
      .attr("transform", d => `translate(${d.x}, ${d.y - radius - 2})`);

    badge.append("rect")
      .attr("x", -10).attr("y", -8)
      .attr("width", 20).attr("height", 10)
      .attr("rx", 4)
      .attr("fill", d => {
        if (d.layer === 0) return "#1e3a8a";
        if (d.layer === layers.length - 1) return "#064e3b";
        return "#312e81";
      });

    badge.append("text")
      .attr("text-anchor", "middle")
      .attr("y", -1)
      .attr("font-size", "7.5px")
      .attr("font-weight", "black")
      .attr("fill", "white")
      .text(d => `N${d.index}`);

    // 图例说明
    const legend = svg.append("g")
      .attr("transform", `translate(${width - 160}, ${height - 110})`);

    legend.append("rect")
      .attr("width", 145).attr("height", 95)
      .attr("rx", 12)
      .attr("fill", "white")
      .attr("fill-opacity", 0.95)
      .attr("stroke", "#cbd5e1")
      .attr("stroke-width", 1.5);

    legend.append("text")
      .attr("x", 12).attr("y", 22)
      .attr("font-size", "10px")
      .attr("font-weight", "black")
      .attr("fill", "#0f172a")
      .attr("class", "uppercase tracking-widest")
      .text("神经网络图例");

    legend.append("line")
      .attr("x1", 12).attr("y1", 38).attr("x2", 42).attr("y2", 38)
      .attr("stroke", "#1e40af").attr("stroke-width", 3.5);
    legend.append("text").attr("x", 48).attr("y", 41).attr("font-size", "9px").attr("font-weight", "black").attr("fill", "#334155").text("正权重 (兴奋)");

    legend.append("line")
      .attr("x1", 12).attr("y1", 53).attr("x2", 42).attr("y2", 53)
      .attr("stroke", "#991b1b").attr("stroke-width", 3.5);
    legend.append("text").attr("x", 48).attr("y", 56).attr("font-size", "9px").attr("font-weight", "black").attr("fill", "#334155").text("负权重 (抑制)");

    legend.append("circle").attr("cx", 27).attr("cy", 75).attr("r", 10).attr("fill", "#f8fafc").attr("stroke", "#475569").attr("stroke-width", 1.5);
    legend.append("text").attr("x", 48).attr("y", 78).attr("font-size", "9px").attr("font-weight", "black").attr("fill", "#334155").text("Σ 求和 | σ 激活");

  }, [layers, weights]);

  return (
    <div className="w-full h-full bg-white rounded-xl shadow-inner border border-blue-100 overflow-hidden relative">
      <div className="absolute top-4 left-4 flex items-center gap-2">
         <div className="w-2.5 h-2.5 bg-blue-700 rounded-full animate-pulse shadow-sm shadow-blue-200"></div>
         <span className="text-[11px] text-slate-900 font-black uppercase tracking-widest pointer-events-none">实时物理神经元模拟</span>
      </div>
      <svg ref={svgRef} className="w-full h-full" />
    </div>
  );
};

export default NetworkGraph;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ScatterChart, Scatter, Legend, ReferenceLine, Label } from 'recharts';
import { BPNetwork } from './services/bpEngine';
import NetworkGraph from './components/NetworkGraph';
import { getAIInsights, ModelType } from './services/geminiService';

const App: React.FC = () => {
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [sampleSize, setSampleSize] = useState(120);
  const [stopThreshold, setStopThreshold] = useState(0.005); 
  const [trainData, setTrainData] = useState<{ input: number[], output: number[] }[]>([]);
  const [testData, setTestData] = useState<{ input: number[], output: number[] }[]>([]);
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);
  const [testResults, setTestResults] = useState<any[]>([]);
  const [isPredicting, setIsPredicting] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  // AI 状态管理
  const [manualKey, setManualKey] = useState("");
  const [selectedModel, setSelectedModel] = useState<ModelType>('gemini_2_5');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const trainingRef = useRef<any>(null);

  const generateData = useCallback(() => {
    const inputDim = layers[0];
    const outputDim = layers[layers.length - 1];
    const newData = Array.from({ length: sampleSize }, () => {
      const input = Array.from({ length: inputDim }, () => Math.random() * 2 - 1);
      const output = Array.from({ length: outputDim }, (_, i) => {
        const factor = i === 0 ? 1 : -0.7;
        const base = Math.sin(input[0] * Math.PI) * Math.cos((input[1] || 1) * Math.PI * factor);
        return Math.max(0.1, Math.min(0.9, (base + (i * 0.2) + 1) / 2)); 
      });
      return { input, output };
    });

    const splitIdx = Math.floor(newData.length * 0.8);
    setTrainData(newData.slice(0, splitIdx));
    setTestData(newData.slice(splitIdx));

    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setTestResults([]);
    setAiInsight("");
    setIsTraining(false);
  }, [layers, learningRate, sampleSize]);

  const runEvaluation = useCallback(() => {
    if (!network || testData.length === 0) return;
    setIsPredicting(true);

    setTimeout(() => {
      const outputDim = layers[layers.length - 1];
      const results = testData.map((d) => {
        const activations = network.feedForward(d.input);
        const predicted = activations[activations.length - 1];
        if (outputDim === 1) {
          return { x: d.output[0], y: predicted[0] };
        } else {
          return {
            actualX: d.output[0],
            actualY: d.output[1],
            predX: predicted[0],
            predY: predicted[1]
          };
        }
      });
      setTestResults(results);
      setIsPredicting(false);
    }, 300);
  }, [network, testData, layers]);

  useEffect(() => {
    generateData();
  }, [layers[0], layers[2], sampleSize, generateData]);

  const trainStep = useCallback(() => {
    if (!network || trainData.length === 0) return;
    let totalLoss = 0;
    trainData.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });
    const avgLoss = totalLoss / trainData.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);

    if (avgLoss <= stopThreshold) {
      setIsTraining(false);
      return;
    }

    if (epoch % 5 === 0) {
      setHistory(prev => [...prev.slice(-99), { epoch, loss: avgLoss }]);
    }
  }, [network, epoch, trainData, stopThreshold]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 20);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handleGetInsight = async () => {
    if (!manualKey && !process.env.API_KEY) {
      setIsSettingsOpen(true);
      return;
    }
    setIsAiLoading(true);
    const result = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss }, selectedModel, manualKey);

    if (result === "ERROR_KEY_NOT_FOUND") {
      setAiInsight("提示：API 密钥校验失败，请检查手工输入的密钥是否正确。");
      setIsSettingsOpen(true);
    } else {
      setAiInsight(result || "");
    }
    setIsAiLoading(false);
  };

  const getModelLabel = () => {
    switch(selectedModel) {
      case 'gemini_2_5': return 'Gemini 2.5 Standard';
      case 'deepseek_basic': return 'DeepSeek 基础版';
      default: return '未知引擎';
    }
  };

  const outputDim = layers[layers.length - 1];

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6 font-sans select-none text-slate-800">
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200">
            <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z"></path></svg>
          </div>
          <div>
            <h1 className="text-3xl font-extrabold text-blue-700 tracking-tight">NeuralLab</h1>
            <p className="text-slate-600 text-[10px] mt-0.5 font-bold uppercase tracking-[0.2em]">BP 神经网络实验室</p>
          </div>
        </div>
        <div className="flex gap-3 mt-4 md:mt-0">
          <button onClick={() => setIsTraining(!isTraining)} className={`px-8 py-2.5 rounded-full font-bold transition-all shadow-md flex items-center gap-2 ${isTraining ? 'bg-amber-500 text-white hover:bg-amber-600 scale-105' : 'bg-blue-600 text-white hover:bg-blue-700'}`}>
            {isTraining ? <><span className="w-2 h-2 bg-white rounded-full animate-ping"></span> 训练中</> : <><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M4.5 3L15.5 10L4.5 17V3Z"/></svg> 启动训练</>}
          </button>
          <button onClick={generateData} className="px-6 py-2.5 rounded-full bg-white border border-slate-300 text-slate-800 font-bold hover:bg-slate-50 transition-all">刷新神经网络图</button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* 左侧控制栏 */}
        <section className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-sm font-black mb-5 flex items-center gap-2 text-slate-900 uppercase tracking-widest"><span className="w-1.5 h-4 bg-blue-500 rounded-full"></span> 模型构建 (Neurons)</h2>
            <div className="space-y-6">
              {[
                { label: '输入层', key: 0, max: 5 },
                { label: '隐藏层', key: 1, max: 12 },
                { label: '输出层', key: 2, max: 2, min: 1 }
              ].map(layer => (
                <div key={layer.key}>
                  <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-500"><span>{layer.label}</span><span className="text-blue-700 font-mono text-sm">{layers[layer.key]}</span></div>
                  <input type="range" min={layer.min || 1} max={layer.max} value={layers[layer.key]} onChange={e => {
                    const newLayers = [...layers];
                    newLayers[layer.key] = parseInt(e.target.value);
                    setLayers(newLayers);
                  }} className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600" />
                </div>
              ))}
              <div className="pt-2">
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-500"><span>学习率 (Alpha)</span><span className="text-blue-700 font-mono text-sm">{learningRate.toFixed(2)}</span></div>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div className="pt-2 border-t border-slate-100">
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-500"><span>收敛阈值 (Stop at)</span><span className="text-red-600 font-mono text-sm">{stopThreshold.toFixed(2)}</span></div>
                <input type="range" min="0.0001" max="0.05" step="0.0005" value={stopThreshold} onChange={e => setStopThreshold(parseFloat(e.target.value))} className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-red-400" />
                <p className="text-[10px] text-slate-600 mt-2 italic font-medium">提示：当损失 (MSE) 低于此值时，训练自动停止。</p>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-sm font-black mb-5 flex items-center gap-2 text-slate-900 uppercase tracking-widest"><span className="w-1.5 h-4 bg-emerald-500 rounded-full"></span> 样本生成 (Dataset)</h2>
            <div className="space-y-6">
              <div>
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-500">
                  <span>样本总量 (Size)</span>
                  <span className="text-emerald-700 font-mono text-sm">{sampleSize}</span>
                </div>
                <input 
                  type="range" 
                  min="50" 
                  max="1000" 
                  step="10" 
                  value={sampleSize} 
                  onChange={e => setSampleSize(parseInt(e.target.value))} 
                  className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-500" 
                />
              </div>
              <div className="bg-slate-50 p-3 rounded-xl border border-slate-100 space-y-2">
                <div className="flex justify-between items-center">
                  <span className="text-[10px] font-bold text-slate-500">训练集比例</span>
                  <span className="text-[10px] font-black text-slate-700">80% ({Math.floor(sampleSize * 0.8)})</span>
                </div>
                <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden flex">
                  <div className="h-full bg-emerald-500" style={{ width: '80%' }}></div>
                  <div className="h-full bg-blue-400" style={{ width: '20%' }}></div>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-[10px] font-bold text-slate-500">测试集比例</span>
                  <span className="text-[10px] font-black text-slate-700">20% ({sampleSize - Math.floor(sampleSize * 0.8)})</span>
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white/40 border border-slate-100 p-6 rounded-3xl flex-grow flex flex-col justify-start">
            <h2 className="text-[11px] font-black mb-6 flex items-center gap-2 uppercase tracking-[0.2em] text-slate-600"><span className="w-4 h-[1px] bg-slate-300"></span> BP 神经网络理论</h2>
            <div className="space-y-6 text-[12px] leading-relaxed text-slate-700 font-medium">
              <section className="mb-2 px-1">
                <p className="text-slate-800 leading-relaxed">
                  BP 神经网络是一种按误差反向传播算法训练的多层前向网络，通过梯度下降法自发调整权重以最小化输出误差。
                </p>
              </section>
              <section className="border-l-2 border-blue-200 pl-4 py-1">
                <h3 className="font-bold text-slate-900 mb-2 italic">前向传播算法</h3>
                <div className="font-mono bg-white/70 p-3 rounded-xl text-blue-800 border border-blue-100 shadow-inner">
                  a<sub>j</sub> = σ( Σ w<sub>jk</sub> a<sub>k</sub> + b<sub>j</sub> )
