import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface NetworkGraphProps {
  layers: number[];
  weights: number[][][];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ layers, weights }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;
    // 增加顶部边距以容纳标签并创建“空行”感
    const marginTop = 100; 
    const marginBottom = 80;
    const marginSide = 80;

    // 获取权重最大绝对值用于归一化
    let maxAbsWeight = 0;
    weights.forEach(layer => layer.forEach(neuron => neuron.forEach(w => {
      const absW = Math.abs(w);
      if (absW > maxAbsWeight) maxAbsWeight = absW;
    })));
    if (maxAbsWeight === 0) maxAbsWeight = 1;

    // 定义滤镜和箭头
    const defs = svg.append("defs");

    // 1. 节点外部阴影
    const filter = defs.append("filter")
      .attr("id", "drop-shadow")
      .attr("x", "-50%")
      .attr("y", "-50%")
      .attr("width", "200%")
      .attr("height", "200%");
    filter.append("feDropShadow")
      .attr("dx", "0")
      .attr("dy", "2")
      .attr("stdDeviation", "3")
      .attr("flood-color", "#000000")
      .attr("flood-opacity", "0.15");

    // 2. 节点内部渐变 (根据层级)
    const createGradient = (id: string, color1: string, color2: string) => {
      const grad = defs.append("linearGradient")
        .attr("id", id)
        .attr("x1", "0%").attr("y1", "0%")
        .attr("x2", "0%").attr("y2", "100%");
      grad.append("stop").attr("offset", "0%").attr("stop-color", color1);
      grad.append("stop").attr("offset", "100%").attr("stop-color", color2);
    };
    createGradient("grad-input", "#eff6ff", "#dbeafe");
    createGradient("grad-hidden", "#f5f3ff", "#ede9fe");
    createGradient("grad-output", "#ecfdf5", "#d1fae5");

    // 3. 有向箭头
    defs.append("marker")
      .attr("id", "arrow-head")
      .attr("viewBox", "0 -5 10 10")
      .attr("refX", 32)
      .attr("refY", 0)
      .attr("markerWidth", 5)
      .attr("markerHeight", 5)
      .attr("orient", "auto")
      .append("path")
      .attr("d", "M0,-5L10,0L0,5")
      .attr("fill", "#1e293b");

    const layerSpacing = (width - 2 * marginSide) / (layers.length - 1 || 1);

    const nodes: any[] = [];
    const nodeMap: { [key: string]: any } = {};

    // 绘制层级标题 - 将 y 坐标下移至 65，并在顶部增加间距
    layers.forEach((_, lIdx) => {
      const x = marginSide + lIdx * layerSpacing;
      let label = "隐藏层 (Hidden)";
      let colorClass = "fill-indigo-950";
      if (lIdx === 0) {
        label = "输入层 (Input)";
        colorClass = "fill-blue-950";
      } else if (lIdx === layers.length - 1) {
        label = "输出层 (Output)";
        colorClass = "fill-emerald-950";
      }

      svg.append("text")
        .attr("x", x)
        .attr("y", 65) // 下移标题位置，与顶部标签拉开距离
        .attr("text-anchor", "middle")
        .attr("font-size", "11px")
        .attr("font-weight", "900")
        .attr("class", `${colorClass} uppercase tracking-[0.3em]`)
        .text(label);
    });

    // 创建节点坐标
    layers.forEach((count, lIdx) => {
      const x = marginSide + lIdx * layerSpacing;
      const vertSpacing = (height - marginTop - marginBottom) / (count || 1);
      const startY = marginTop + (height - marginTop - marginBottom - (count - 1) * vertSpacing) / 2;

      for (let i = 0; i < count; i++) {
        const id = `l${lIdx}n${i}`;
        const node = { id, x, y: startY + i * vertSpacing, layer: lIdx, index: i + 1 };
        nodes.push(node);
        nodeMap[id] = node;
      }
    });

    // 绘制权重连接线
    const edges: any[] = [];
    for (let l = 0; l < weights.length; l++) {
      for (let j = 0; j < weights[l].length; j++) {
        for (let k = 0; k < weights[l][j].length; k++) {
          if (nodeMap[`l${l}n${k}`] && nodeMap[`l${l+1}n${j}`]) {
            edges.push({
              source: nodeMap[`l${l}n${k}`],
              target: nodeMap[`l${l+1}n${j}`],
              weight: weights[l][j][k]
            });
          }
        }
      }
    }

    const lineGroup = svg.append("g")
      .selectAll("line")
      .data(edges)
      .enter()
      .append("line")
      .attr("x1", d => d.source.x)
      .attr("y1", d => d.source.y)
      .attr("x2", d => d.target.x)
      .attr("y2", d => d.target.y)
      .attr("stroke", d => d.weight > 0 ? "#1e40af" : "#b91c1c")
      .attr("stroke-width", d => (Math.abs(d.weight) / maxAbsWeight) * 4 + 0.6)
      .attr("opacity", d => (Math.abs(d.weight) / maxAbsWeight) * 0.7 + 0.2)
      .attr("marker-end", "url(#arrow-head)");

    // 为连接线添加原生 Tooltip 提示
    lineGroup.append("title")
      .text(d => `权重 (Weight): ${d.weight.toFixed(2)}`);

    // 绘制高级神经元模型 (Σ | σ)
    const nodeGroups = svg.append("g")
      .selectAll("g")
      .data(nodes)
      .enter()
      .append("g")
      .attr("filter", "url(#drop-shadow)");

    const radius = 22;
    nodeGroups.append("circle")
      .attr("cx", d => d.x)
      .attr("cy", d => d.y)
      .attr("r", radius)
      .attr("fill", d => {
        if (d.layer === 0) return "url(#grad-input)";
        if (d.layer === layers.length - 1) return "url(#grad-output)";
        return "url(#grad-hidden)";
      })
      .attr("stroke", d => {
        if (d.layer === 0) return "#1e40af";
        if (d.layer === layers.length - 1) return "#065f46";
        return "#3730a3";
      })
      .attr("stroke-width", 2);

    nodeGroups.append("line")
      .attr("x1", d => d.x).attr("y1", d => d.y - radius + 5)
      .attr("x2", d => d.x).attr("y2", d => d.y + radius - 5)
      .attr("stroke", d => {
        if (d.layer === 0) return "#3b82f6";
        if (d.layer === layers.length - 1) return "#10b981";
        return "#6366f1";
      })
      .attr("stroke-width", 1.2)
      .attr("stroke-dasharray", "2 1");

    nodeGroups.append("text")
      .attr("x", d => d.x - 8)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px")
      .attr("font-family", "serif")
      .attr("font-weight", "900")
      .attr("fill", d => d.layer === 0 ? "#0f172a" : d.layer === layers.length - 1 ? "#064e3b" : "#1e1b4b")
      .text("Σ");

    nodeGroups.append("text")
      .attr("x", d => d.x + 8)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px")
      .attr("font-family", "serif")
      .attr("font-weight", "900")
      .attr("fill", d => d.layer === 0 ? "#0f172a" : d.layer === layers.length - 1 ? "#064e3b" : "#1e1b4b")
      .text("σ");

    const badge = nodeGroups.append("g")
      .attr("transform", d => `translate(${d.x}, ${d.y - radius - 2})`);

    badge.append("rect")
      .attr("x", -10).attr("y", -8)
      .attr("width", 20).attr("height", 10)
      .attr("rx", 4)
      .attr("fill", d => {
        if (d.layer === 0) return "#1e3a8a";
        if (d.layer === layers.length - 1) return "#064e3b";
        return "#312e81";
      });

    badge.append("text")
      .attr("text-anchor", "middle")
      .attr("y", -1)
      .attr("font-size", "7.5px")
      .attr("font-weight", "black")
      .attr("fill", "white")
      .text(d => `N${d.index}`);

    // 图例说明
    const legend = svg.append("g")
      .attr("transform", `translate(${width - 160}, ${height - 110})`);

    legend.append("rect")
      .attr("width", 145).attr("height", 95)
      .attr("rx", 12)
      .attr("fill", "white")
      .attr("fill-opacity", 0.95)
      .attr("stroke", "#94a3b8")
      .attr("stroke-width", 1.5);

    legend.append("text")
      .attr("x", 12).attr("y", 22)
      .attr("font-size", "10px")
      .attr("font-weight", "black")
      .attr("fill", "#020617")
      .attr("class", "uppercase tracking-widest")
      .text("神经网络图例");

    legend.append("line")
      .attr("x1", 12).attr("y1", 38).attr("x2", 42).attr("y2", 38)
      .attr("stroke", "#1e40af").attr("stroke-width", 3.5);
    legend.append("text").attr("x", 48).attr("y", 41).attr("font-size", "9px").attr("font-weight", "900").attr("fill", "#1e293b").text("正权重 (兴奋)");

    legend.append("line")
      .attr("x1", 12).attr("y1", 53).attr("x2", 42).attr("y2", 53)
      .attr("stroke", "#991b1b").attr("stroke-width", 3.5);
    legend.append("text").attr("x", 48).attr("y", 56).attr("font-size", "9px").attr("font-weight", "900").attr("fill", "#1e293b").text("负权重 (抑制)");

    legend.append("circle").attr("cx", 27).attr("cy", 75).attr("r", 10).attr("fill", "#f8fafc").attr("stroke", "#1e293b").attr("stroke-width", 1.5);
    legend.append("text").attr("x", 48).attr("y", 78).attr("font-size", "9px").attr("font-weight", "900").attr("fill", "#1e293b").text("Σ 求和 | σ 激活");

  }, [layers, weights]);

  return (
    <div className="w-full h-full bg-white rounded-xl shadow-inner border border-blue-100 overflow-hidden relative">
      <div className="absolute top-4 left-4 flex items-center gap-2">
         <div className="w-2.5 h-2.5 bg-blue-700 rounded-full animate-pulse shadow-sm shadow-blue-200"></div>
         <span className="text-[11px] text-slate-950 font-black uppercase tracking-widest pointer-events-none">实时物理神经元模拟</span>
      </div>
      <svg ref={svgRef} className="w-full h-full" />
    </div>
  );
};

export default NetworkGraph;

{
  "name": "bp-neural-lab",
  "version": "1.0.0",
  "private": true,
  "engines": {
    "node": ">=18.0.0"
  },
  "dependencies": {
    "react": "^19.2.3",
    "react-dom": "^19.2.3",
    "d3": "^7.9.0",
    "recharts": "^3.6.0",
    "@google/genai": "^1.34.0"
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ScatterChart, Scatter, Legend, ReferenceLine, Label } from 'recharts';
import { BPNetwork } from './services/bpEngine';
import NetworkGraph from './components/NetworkGraph';
import { getAIInsights, ModelType } from './services/geminiService';

const App: React.FC = () => {
  const [layers, setLayers] = useState<number[]>([2, 4, 1]);
  const [learningRate, setLearningRate] = useState(0.5);
  const [sampleSize, setSampleSize] = useState(120);
  const [stopThreshold, setStopThreshold] = useState(0.01); 
  const [trainData, setTrainData] = useState<{ input: number[], output: number[] }[]>([]);
  const [testData, setTestData] = useState<{ input: number[], output: number[] }[]>([]);
  const [network, setNetwork] = useState<BPNetwork>(new BPNetwork([2, 4, 1], 0.5));
  const [isTraining, setIsTraining] = useState(false);
  const [history, setHistory] = useState<{ epoch: number; loss: number }[]>([]);
  const [currentLoss, setCurrentLoss] = useState(0);
  const [epoch, setEpoch] = useState(0);
  const [testResults, setTestResults] = useState<any[]>([]);
  const [isPredicting, setIsPredicting] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>("");
  const [isAiLoading, setIsAiLoading] = useState(false);

  // 用于强制触发 NetworkGraph 更新的计数器
  const [tick, setTick] = useState(0);

  const [manualKey, setManualKey] = useState("");
  const [selectedModel, setSelectedModel] = useState<ModelType>('gemini_2_5');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const trainingRef = useRef<any>(null);

  const generateData = useCallback(() => {
    const inputDim = layers[0];
    const outputDim = layers[layers.length - 1];
    const newData = Array.from({ length: sampleSize }, () => {
      const input = Array.from({ length: inputDim }, () => Math.random() * 2 - 1);
      const output = Array.from({ length: outputDim }, (_, i) => {
        const factor = i === 0 ? 1 : -0.7;
        const base = Math.sin(input[0] * Math.PI) * Math.cos((input[1] || 1) * Math.PI * factor);
        return Math.max(0.1, Math.min(0.9, (base + (i * 0.2) + 1) / 2)); 
      });
      return { input, output };
    });

    const splitIdx = Math.floor(newData.length * 0.8);
    setTrainData(newData.slice(0, splitIdx));
    setTestData(newData.slice(splitIdx));

    const newNet = new BPNetwork(layers, learningRate);
    setNetwork(newNet);
    setHistory([]);
    setEpoch(0);
    setCurrentLoss(0);
    setTestResults([]);
    setAiInsight("");
    setIsTraining(false);
    setTick(t => t + 1);
  }, [layers, learningRate, sampleSize]);

  const runEvaluation = useCallback(() => {
    if (!network || testData.length === 0) return;
    setIsPredicting(true);

    setTimeout(() => {
      const outputDim = layers[layers.length - 1];
      const results = testData.map((d) => {
        const activations = network.feedForward(d.input);
        const predicted = activations[activations.length - 1];
        if (outputDim === 1) {
          return { x: d.output[0], y: predicted[0] };
        } else {
          return {
            actualX: d.output[0],
            actualY: d.output[1],
            predX: predicted[0],
            predY: predicted[1]
          };
        }
      });
      setTestResults(results);
      setIsPredicting(false);
    }, 300);
  }, [network, testData, layers]);

  useEffect(() => {
    generateData();
  }, [layers[0], layers[2], sampleSize, generateData]);

  const trainStep = useCallback(() => {
    if (!network || trainData.length === 0) return;
    let totalLoss = 0;
    trainData.forEach(point => {
      totalLoss += network.train(point.input, point.output);
    });
    const avgLoss = totalLoss / trainData.length;
    setCurrentLoss(avgLoss);
    setEpoch(prev => prev + 1);

    // 训练中定期触发重绘以展示动态权重
    if (epoch % 2 === 0) {
      setTick(t => t + 1);
    }

    if (avgLoss <= stopThreshold) {
      setIsTraining(false);
      setTick(t => t + 1); // 结束时强制刷新一次
      return;
    }

    if (epoch % 5 === 0) {
      setHistory(prev => [...prev.slice(-99), { epoch, loss: avgLoss }]);
    }
  }, [network, epoch, trainData, stopThreshold]);

  useEffect(() => {
    if (isTraining) {
      trainingRef.current = setInterval(trainStep, 20);
    } else {
      clearInterval(trainingRef.current);
    }
    return () => clearInterval(trainingRef.current);
  }, [isTraining, trainStep]);

  const handleGetInsight = async () => {
    if (!manualKey && !process.env.API_KEY) {
      setIsSettingsOpen(true);
      return;
    }
    setIsAiLoading(true);
    const result = await getAIInsights({ layers, learningRate }, { epoch, loss: currentLoss }, selectedModel, manualKey);

    if (result === "ERROR_KEY_NOT_FOUND") {
      setAiInsight("提示：API 密钥校验失败，请检查手工输入的密钥是否正确。");
      setIsSettingsOpen(true);
    } else {
      setAiInsight(result || "");
    }
    setIsAiLoading(false);
  };

  const getModelLabel = () => {
    switch(selectedModel) {
      case 'gemini_2_5': return 'Gemini 2.5 Standard';
      case 'deepseek_basic': return 'DeepSeek 基础版';
      default: return '未知引擎';
    }
  };

  const outputDim = layers[layers.length - 1];

  return (
    <div className="min-h-screen p-4 md:p-8 bg-gray-50 flex flex-col gap-6 font-sans select-none text-slate-800">
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200">
            <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z"></path></svg>
          </div>
          <div>
            <h1 className="text-3xl font-extrabold text-blue-700 tracking-tight">NeuralLab</h1>
            <p className="text-slate-600 text-[10px] mt-0.5 font-bold uppercase tracking-[0.2em]">BP 神经网络实验室</p>
          </div>
        </div>
        <div className="flex gap-3 mt-4 md:mt-0">
          <button onClick={() => setIsTraining(!isTraining)} className={`px-8 py-2.5 rounded-full font-bold transition-all shadow-md flex items-center gap-2 ${isTraining ? 'bg-amber-500 text-white hover:bg-amber-600 scale-105' : 'bg-blue-600 text-white hover:bg-blue-700'}`}>
            {isTraining ? <><span className="w-2 h-2 bg-white rounded-full animate-ping"></span> 训练中</> : <><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M4.5 3L15.5 10L4.5 17V3Z"/></svg> 启动训练</>}
          </button>
          <button onClick={generateData} className="px-6 py-2.5 rounded-full bg-white border border-slate-300 text-slate-800 font-bold hover:bg-slate-50 transition-all">刷新神经网络图</button>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* 控制面板 */}
        <section className="lg:col-span-3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-sm font-black mb-5 flex items-center gap-2 text-slate-900 uppercase tracking-widest"><span className="w-1.5 h-4 bg-blue-500 rounded-full"></span> 模型参数</h2>
            <div className="space-y-6">
              {[
                { label: '输入层', key: 0, max: 5 },
                { label: '隐藏层', key: 1, max: 12 },
                { label: '输出层', key: 2, max: 2, min: 1 }
              ].map(layer => (
                <div key={layer.key}>
                  <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-500"><span>{layer.label}</span><span className="text-blue-700 font-mono text-sm">{layers[layer.key]}</span></div>
                  <input type="range" min={layer.min || 1} max={layer.max} value={layers[layer.key]} onChange={e => {
                    const newLayers = [...layers];
                    newLayers[layer.key] = parseInt(e.target.value);
                    setLayers(newLayers);
                  }} className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600" />
                </div>
              ))}
              <div className="pt-2">
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-500"><span>学习率 (Alpha)</span><span className="text-blue-700 font-mono text-sm">{learningRate.toFixed(2)}</span></div>
                <input type="range" min="0.01" max="1" step="0.01" value={learningRate} onChange={e => setLearningRate(parseFloat(e.target.value))} className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div className="pt-2 border-t border-slate-100">
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-500"><span>收敛阈值</span><span className="text-red-600 font-mono text-sm">{stopThreshold.toFixed(2)}</span></div>
                <input type="range" min="0.005" max="0.1" step="0.005" value={stopThreshold} onChange={e => setStopThreshold(parseFloat(e.target.value))} className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-red-400" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h2 className="text-sm font-black mb-5 flex items-center gap-2 text-slate-900 uppercase tracking-widest"><span className="w-1.5 h-4 bg-emerald-500 rounded-full"></span> 样本配置</h2>
            <div className="space-y-6">
              <div>
                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-500">
                  <span>样本总量</span>
                  <span className="text-emerald-700 font-mono text-sm">{sampleSize}</span>
                </div>
                <input type="range" min="50" max="500" step="10" value={sampleSize} onChange={e => setSampleSize(parseInt(e.target.value))} className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-500" />
              </div>
            </div>
          </div>
        </section>

        {/* 核心可视化 */}
        <section className="lg:col-span-6 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow min-h-[420px] flex flex-col relative overflow-hidden">
             <h2 className="text-sm font-black mb-4 flex items-center gap-2 text-slate-900 uppercase tracking-widest"><span className="w-1.5 h-4 bg-indigo-500 rounded-full"></span> 动态网络拓扑 (权重监控)</h2>
            <div className="flex-grow"><NetworkGraph key={tick} layers={layers} weights={network.weights} /></div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[280px] flex flex-col">
              <h2 className="text-xs font-black mb-4 flex items-center justify-between text-slate-800 uppercase tracking-wider">
                <div className="flex items-center gap-2"><span className="w-1.5 h-4 bg-red-400 rounded-full"></span> 均方误差 (MSE)</div>
                <div className="text-[10px] text-slate-600 font-mono font-bold">{currentLoss.toFixed(2)}</div>
              </h2>
              <div className="flex-grow">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={history}><CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" /><XAxis dataKey="epoch" hide /><YAxis domain={[0, 'auto']} tick={{fontSize: 9, fill: '#64748b', fontWeight: 'bold'}} axisLine={false} tickLine={false} /><Tooltip contentStyle={{borderRadius: '12px', border: 'none', fontSize: '10px'}} /><Line type="monotone" dataKey="loss" stroke="#ef4444" strokeWidth={2.5} dot={false} isAnimationActive={false} /></LineChart>
                </ResponsiveContainer>
              </div>
            </div>
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-[280px] flex flex-col">
              <h2 className="text-xs font-black mb-4 flex items-center justify-between text-slate-800 uppercase tracking-wider">
                <div className="flex items-center gap-2"><span className="w-1.5 h-4 bg-emerald-400 rounded-full"></span> 预测回归分析</div>
                <button onClick={runEvaluation} disabled={isPredicting || isTraining} className="text-[10px] px-3 py-1 rounded-full bg-blue-50 text-blue-700 border border-blue-200 hover:bg-blue-100 transition-colors font-bold">测试评估</button>
              </h2>
              <div className="flex-grow relative">
                <ResponsiveContainer width="100%" height="100%">
                  <ScatterChart margin={{ top: 10, right: 10, bottom: 20, left: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f5f5f5" />
                    <XAxis type="number" dataKey="x" domain={[0, 1]} tick={{fontSize: 8}} />
                    <YAxis type="number" dataKey="y" domain={[0, 1]} tick={{fontSize: 8}} />
                    <ReferenceLine segment={[{ x: 0, y: 0 }, { x: 1, y: 1 }]} stroke="#6366f1" strokeWidth={1} strokeDasharray="4 4" />
                    <Scatter name="预测点" data={testResults} fill="#3b82f6" fillOpacity={0.6} />
                  </ScatterChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </section>

        {/* AI 诊断 */}
        <section className="lg:col-span-3 flex flex-col relative">
          <div className="bg-white p-6 rounded-2xl shadow-xl shadow-slate-200/50 flex-grow flex flex-col border border-slate-100 overflow-hidden relative">
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-600 rounded-lg shadow-md shadow-indigo-100">
                  <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                </div>
                <h2 className="text-lg font-black text-slate-900 tracking-tight">AI 诊断报告</h2>
              </div>
              <button onClick={() => setIsSettingsOpen(true)} className="p-2 text-slate-400 hover:text-indigo-600 transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path></svg></button>
            </div>

            <div className="flex-grow flex flex-col">
              <div className="flex-grow overflow-y-auto text-[11px] leading-relaxed text-slate-800 font-medium custom-scrollbar pr-1">
                {aiInsight ? (
                  <div className="prose prose-sm animate-in fade-in slide-in-from-bottom-2">
                    <div dangerouslySetInnerHTML={{ __html: aiInsight.replace(/\n/g, '<br/>') }} />
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center italic text-center text-slate-400 py-20">
                    <p className="text-xs font-black mb-1">等待诊断数据...</p>
                    <p className="text-[10px]">训练过程中点击下方按钮获取建议</p>
                  </div>
                )}
              </div>
              <button onClick={handleGetInsight} disabled={isAiLoading || epoch === 0} className={`w-full py-3.5 mt-4 rounded-xl font-black text-xs text-white shadow-xl transition-all ${isAiLoading || epoch === 0 ? 'bg-slate-200 cursor-not-allowed' : 'bg-indigo-600 hover:scale-[1.02]'}`}>
                {isAiLoading ? '分析中...' : '深度大模型诊断'}
              </button>
            </div>

            {isSettingsOpen && (
              <div className="absolute inset-0 z-30 bg-white/95 backdrop-blur-sm p-6 flex flex-col">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">诊断配置</h3>
                  <button onClick={() => setIsSettingsOpen(false)} className="text-slate-400 hover:text-slate-900 transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg></button>
                </div>
                <div className="space-y-6">
                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase block mb-2">API 密钥</label>
                    <input type="password" value={manualKey} onChange={(e) => setManualKey(e.target.value)} placeholder="粘贴 API 密钥..." className="w-full p-3 rounded-xl border border-slate-200 text-xs font-mono focus:border-indigo-500 outline-none" />
                  </div>
                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase block mb-2">选择模型</label>
                    <div className="grid grid-cols-1 gap-2">
                      <button onClick={() => setSelectedModel('gemini_2_5')} className={`p-3 rounded-xl border text-left text-[11px] font-bold ${selectedModel === 'gemini_2_5' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-100 bg-white'}`}>Gemini 2.5 Flash</button>
                      <button onClick={() => setSelectedModel('deepseek_basic')} className={`p-3 rounded-xl border text-left text-[11px] font-bold ${selectedModel === 'deepseek_basic' ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-slate-100 bg-white'}`}>Gemini Flash Lite</button>
                    </div>
                  </div>
                  <button onClick={() => setIsSettingsOpen(false)} className="w-full py-3 mt-4 rounded-xl bg-slate-900 text-white text-xs font-black">完成</button>
                </div>
              </div>
            )}
          </div>
        </section>
      </main>

      <footer className="mt-2 text-center text-[9px] text-slate-400 uppercase tracking-[0.4em] font-bold">
        NeuralLab Lab &copy; 2024 · POWERED BY GOOGLE GENAI
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        input[type=range]::-webkit-slider-thumb { -webkit-appearance: none; height: 14px; width: 14px; border-radius: 50%; background: #2563eb; border: 2.5px solid white; box-shadow: 0 1px 4px rgba(0,0,0,0.1); }
      `}</style>
    </div>
  );
};

