import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';

interface NetworkGraphProps {
  layers: number[];
  weights: number[][][];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ layers, weights }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;
    const marginTop = 100; 
    const marginBottom = 80;
    const marginSide = 80;

    // 获取权重极限值用于归一化颜色显示
    let maxAbsWeight = 0;
    weights.forEach(layer => layer.forEach(neuron => neuron.forEach(w => {
      const absW = Math.abs(w);
      if (absW > maxAbsWeight) maxAbsWeight = absW;
    })));
    if (maxAbsWeight === 0) maxAbsWeight = 1;

    const defs = svg.append("defs");

    // 阴影滤镜
    const filter = defs.append("filter")
      .attr("id", "drop-shadow")
      .attr("x", "-50%")
      .attr("y", "-50%")
      .attr("width", "200%")
      .attr("height", "200%");
    filter.append("feDropShadow")
      .attr("dx", "0")
      .attr("dy", "2")
      .attr("stdDeviation", "2.5")
      .attr("flood-color", "#000000")
      .attr("flood-opacity", "0.1");

    // 渐变定义
    const createGradient = (id: string, color1: string, color2: string) => {
      const grad = defs.append("linearGradient")
        .attr("id", id)
        .attr("x1", "0%").attr("y1", "0%")
        .attr("x2", "0%").attr("y2", "100%");
      grad.append("stop").attr("offset", "0%").attr("stop-color", color1);
      grad.append("stop").attr("offset", "100%").attr("stop-color", color2);
    };
    createGradient("grad-input", "#eff6ff", "#dbeafe");
    createGradient("grad-hidden", "#f5f3ff", "#ede9fe");
    createGradient("grad-output", "#ecfdf5", "#d1fae5");

    // 箭头
    defs.append("marker")
      .attr("id", "arrow-head")
      .attr("viewBox", "0 -5 10 10")
      .attr("refX", 32)
      .attr("refY", 0)
      .attr("markerWidth", 5)
      .attr("markerHeight", 5)
      .attr("orient", "auto")
      .append("path")
      .attr("d", "M0,-5L10,0L0,5")
      .attr("fill", "#475569");

    const layerSpacing = (width - 2 * marginSide) / (layers.length - 1 || 1);
    const nodes: any[] = [];
    const nodeMap: { [key: string]: any } = {};

    // 绘制层级标题
    layers.forEach((_, lIdx) => {
      const x = marginSide + lIdx * layerSpacing;
      let label = "隐藏层";
      let colorClass = "fill-indigo-950";
      if (lIdx === 0) { label = "输入层"; colorClass = "fill-blue-950"; }
      else if (lIdx === layers.length - 1) { label = "输出层"; colorClass = "fill-emerald-950"; }

      svg.append("text")
        .attr("x", x)
        .attr("y", 65)
        .attr("text-anchor", "middle")
        .attr("font-size", "11px")
        .attr("font-weight", "900")
        .attr("class", `${colorClass} uppercase tracking-[0.3em]`)
        .text(label);
    });

    // 计算坐标
    layers.forEach((count, lIdx) => {
      const x = marginSide + lIdx * layerSpacing;
      const vertSpacing = (height - marginTop - marginBottom) / (count || 1);
      const startY = marginTop + (height - marginTop - marginBottom - (count - 1) * vertSpacing) / 2;

      for (let i = 0; i < count; i++) {
        const id = `l${lIdx}n${i}`;
        const node = { id, x, y: startY + i * vertSpacing, layer: lIdx, index: i + 1 };
        nodes.push(node);
        nodeMap[id] = node;
      }
    });

    // 绘制连线
    const edges: any[] = [];
    for (let l = 0; l < weights.length; l++) {
      for (let j = 0; j < weights[l].length; j++) {
        for (let k = 0; k < weights[l][j].length; k++) {
          if (nodeMap[`l${l}n${k}`] && nodeMap[`l${l+1}n${j}`]) {
            edges.push({
              source: nodeMap[`l${l}n${k}`],
              target: nodeMap[`l${l+1}n${j}`],
              weight: weights[l][j][k]
            });
          }
        }
      }
    }

    const lineGroup = svg.append("g")
      .selectAll("line")
      .data(edges)
      .enter()
      .append("line")
      .attr("x1", d => d.source.x)
      .attr("y1", d => d.source.y)
      .attr("x2", d => d.target.x)
      .attr("y2", d => d.target.y)
      // 动态颜色：正值为蓝色，负值为红色，根据权重强度变化
      .attr("stroke", d => d.weight > 0 ? d3.interpolateBlues(0.4 + (Math.abs(d.weight)/maxAbsWeight)*0.6) : d3.interpolateReds(0.4 + (Math.abs(d.weight)/maxAbsWeight)*0.6))
      .attr("stroke-width", d => (Math.abs(d.weight) / maxAbsWeight) * 4.5 + 0.8)
      .attr("opacity", d => (Math.abs(d.weight) / maxAbsWeight) * 0.7 + 0.3)
      .attr("marker-end", "url(#arrow-head)");

    lineGroup.append("title")
      .text(d => `权重系数: ${d.weight.toFixed(2)}`);

    // 绘制神经元
    const nodeGroups = svg.append("g")
      .selectAll("g")
      .data(nodes)
      .enter()
      .append("g")
      .attr("filter", "url(#drop-shadow)");

    const radius = 22;
    nodeGroups.append("circle")
      .attr("cx", d => d.x)
      .attr("cy", d => d.y)
      .attr("r", radius)
      .attr("fill", d => {
        if (d.layer === 0) return "url(#grad-input)";
        if (d.layer === layers.length - 1) return "url(#grad-output)";
        return "url(#grad-hidden)";
      })
      .attr("stroke", d => d.layer === 0 ? "#1e40af" : d.layer === layers.length - 1 ? "#065f46" : "#3730a3")
      .attr("stroke-width", 2);

    nodeGroups.append("text")
      .attr("x", d => d.x - 8)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px")
      .attr("font-family", "serif")
      .attr("font-weight", "900")
      .attr("fill", "#020617")
      .text("Σ");

    nodeGroups.append("text")
      .attr("x", d => d.x + 8)
      .attr("y", d => d.y + 4)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px")
      .attr("font-family", "serif")
      .attr("font-weight", "900")
      .attr("fill", "#020617")
      .text("σ");

    // 序号标签
    const badge = nodeGroups.append("g")
      .attr("transform", d => `translate(${d.x}, ${d.y - radius - 2})`);

    badge.append("rect")
      .attr("x", -10).attr("y", -8)
      .attr("width", 20).attr("height", 10)
      .attr("rx", 3)
      .attr("fill", d => d.layer === 0 ? "#1e3a8a" : d.layer === layers.length - 1 ? "#064e3b" : "#312e81");

    badge.append("text")
      .attr("text-anchor", "middle")
      .attr("y", -1)
      .attr("font-size", "7.5px")
      .attr("font-weight", "black")
      .attr("fill", "white")
      .text(d => `N${d.index}`);

    // 图例
    const legend = svg.append("g")
      .attr("transform", `translate(${width - 150}, ${height - 100})`);

    legend.append("rect")
      .attr("width", 140).attr("height", 90)
      .attr("rx", 10)
      .attr("fill", "white")
      .attr("stroke", "#e2e8f0")
      .attr("stroke-width", 1);

    legend.append("text").attr("x", 10).attr("y", 20).attr("font-size", "9px").attr("font-weight", "black").text("可视化说明 (2位精度)");
    legend.append("line").attr("x1", 10).attr("y1", 35).attr("x2", 40).attr("y2", 35).attr("stroke", "#1e40af").attr("stroke-width", 3);
    legend.append("text").attr("x", 45).attr("y", 38).attr("font-size", "8px").attr("font-weight", "bold").text("兴奋权重 (Pos)");
    legend.append("line").attr("x1", 10).attr("y1", 50).attr("x2", 40).attr("y2", 50).attr("stroke", "#b91c1c").attr("stroke-width", 3);
    legend.append("text").attr("x", 45).attr("y", 53).attr("font-size", "8px").attr("font-weight", "bold").text("抑制权重 (Neg)");
    legend.append("circle").attr("cx", 25).attr("cy", 70).attr("r", 8).attr("fill", "#f8fafc").attr("stroke", "#475569").attr("stroke-width", 1);
    legend.append("text").attr("x", 45).attr("y", 73).attr("font-size", "8px").attr("font-weight", "bold").text("神经元 (Σ | σ)");

  }, [layers, weights]);

  return (
    <div className="w-full h-full bg-white rounded-xl shadow-inner border border-blue-50 overflow-hidden relative">
      <div className="absolute top-4 left-4 flex items-center gap-2">
         <div className="w-2.5 h-2.5 bg-blue-700 rounded-full animate-pulse"></div>
         <span className="text-[10px] text-slate-950 font-black uppercase tracking-widest pointer-events-none">实时神经元仿真监控</span>
      </div>
      <svg ref={svgRef} className="w-full h-full" />
    </div>
  );
};

export default NetworkGraph;

