          {/* 可视化中心 */}
          <section className="lg:col-span-6 flex flex-col gap-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex-grow min-h-[450px] flex flex-col relative overflow-visible">
               <h2 className="text-sm font-black mb-4 flex items-center gap-2 text-slate-900 uppercase tracking-widest"><span className="w-1.5 h-4 bg-indigo-500 rounded-full"></span> 神经元拓扑结构 (可视化监控)</h2>
              <div className="flex-grow relative h-full">
                <NetworkGraph layers={layers} weights={network.weights} />
